var documenterSearchIndex = {"docs":
[{"location":"develop/#Developing-Extensions","page":"Developing Extensions","title":"Developing Extensions","text":"ExaModels.jl's API only uses simple julia functions, and thus, implementing the extensions is straightforward. Below, we suggest a good practice for implementing an extension package.\n\nLet's say that we want to implement an extension package for the example problem in Getting Started. An extension package may look like:\n\nRoot\n├───Project.toml\n├── src\n│   └── LuksanVlcekModels.jl\n└── test\n    └── runtest.jl\n\nEach of the files containing\n\n# Project.toml\n\nname = \"LuksanVlcekModels\"\nuuid = \"0c5951a0-f777-487f-ad29-fac2b9a21bf1\"\nauthors = [\"Sungho Shin <sshin@anl.gov>\"]\nversion = \"0.1.0\"\n\n[deps]\nExaModels = \"1037b233-b668-4ce9-9b63-f9f681f55dd2\"\n\n[extras]\nNLPModelsIpopt = \"f4238b75-b362-5c4c-b852-0801c9a21d71\"\nTest = \"8dfed614-e22c-5e08-85e1-65c5234f0b40\"\n\n[targets]\ntest = [\"Test\", \"NLPModelsIpopt\"]\n\n# src/LuksanVlcekModels.jl\n\nmodule LuksanVlcekModels\n\nimport ExaModels\n\nfunction luksan_vlcek_obj(x,i)\n    return 100*(x[i-1]^2-x[i])^2+(x[i-1]-1)^2\nend\n\nfunction luksan_vlcek_con(x,i)\n    return 3x[i+1]^3+2*x[i+2]-5+sin(x[i+1]-x[i+2])sin(x[i+1]+x[i+2])+4x[i+1]-x[i]exp(x[i]-x[i+1])-3\nend\n\nfunction luksan_vlcek_x0(i)\n    return mod(i,2)==1 ? -1.2 : 1.0\nend\n\nfunction luksan_vlcek_model(N; backend = nothing)\n    \n    c = ExaModels.ExaCore(backend, concrete = Val(true))\n    c, x = ExaModels.add_variable(\n        c, N;\n        start = (luksan_vlcek_x0(i) for i=1:N)\n    )\n    c, _ = ExaModels.add_constraint(\n        c,\n        luksan_vlcek_con(x,i)\n        for i in 1:N-2)\n    c, _ = ExaModels.add_objective(c, luksan_vlcek_obj(x,i) for i in 2:N)\n    \n    return ExaModels.ExaModel(c) # returns the model\nend\n\nexport luksan_vlcek_model\n\nend # module LuksanVlcekModels\n\n# test/runtest.jl\n\nusing Test, LuksanVlcekModels, NLPModelsIpopt\n\n@testset \"LuksanVlcekModelsTest\" begin\n    m = luksan_vlcek_model(10)\n    result = ipopt(m)\n\n    @test result.status == :first_order\n    @test result.solution ≈ [\n        -0.9505563573613093\n        0.9139008176388945\n        0.9890905176644905\n        0.9985592422681151\n        0.9998087408802769\n        0.9999745932450963\n        0.9999966246997642\n        0.9999995512524277\n        0.999999944919307\n        0.999999930070643\n    ]\n    @test result.multipliers ≈ [\n        4.1358568305002255\n        -1.876494903703342\n        -0.06556333356358675\n        -0.021931863018312875\n        -0.0019537261317119302\n        -0.00032910445671233547\n        -3.8788212776372465e-5\n        -7.376592164341867e-6\n    ]\nend","category":"section"},{"location":"distillation/#distillation","page":"Example: Distillation Column","title":"Example: Distillation Column","text":"This example demonstrates the use of @add_expr to define reusable subexpressions that simplify complex models.  We compare two formulations of a distillation column: one written by hand and one that uses named subexpressions for readability.","category":"section"},{"location":"distillation/#Subexpressions-in-ExaModels","page":"Example: Distillation Column","title":"Subexpressions in ExaModels","text":"The @add_expr macro (or add_expr) creates an inlined subexpression: a named expression template that is substituted directly wherever it is indexed. No auxiliary variables or extra constraints are added to the problem.\n\n@add_expr(c, s, x[i]^2 for i in 1:n)   # s[i] expands to x[i]^2 at each use site\n\nThe benefit is purely notational: repeated sub-expressions like finite-difference stencils can be named once and reused across many constraints, keeping model code concise without changing the NLP structure.","category":"section"},{"location":"distillation/#Original-Model-(without-subexpressions)","page":"Example: Distillation Column","title":"Original Model (without subexpressions)","text":"This is the original formulation where expressions like (xA[t, i] - xA[t-1, i]) / dt are repeated in multiple constraints.\n\nusing ExaModels, NLPModelsIpopt\n\nfunction distillation_column_model(T = 3; backend = nothing)\n\n    NT = 30\n    FT = 17\n    Ac = 0.5\n    At = 0.25\n    Ar = 1.0\n    D = 0.2\n    F = 0.4\n    ybar = 0.8958\n    ubar = 2.0\n    alpha = 1.6\n    dt = 10 / T\n    xAf = 0.5\n    xA0s = ExaModels.convert_array([(i, 0.5) for i = 0:(NT+1)], backend)\n\n    itr0 = ExaModels.convert_array(collect(Iterators.product(1:T, 1:(FT-1))), backend)\n    itr1 = ExaModels.convert_array(collect(Iterators.product(1:T, (FT+1):NT)), backend)\n    itr2 = ExaModels.convert_array(collect(Iterators.product(0:T, 0:(NT+1))), backend)\n\n    c = ExaCore(; backend, concrete = Val(true))\n\n    @add_var(c, xA, 0:T, 0:(NT+1); start = 0.5)\n    @add_var(c, yA, 0:T, 0:(NT+1); start = 0.5)\n    @add_var(c, u, 0:T; start = 1.0)\n    @add_var(c, V, 0:T; start = 1.0)\n    @add_var(c, L2, 0:T; start = 1.0)\n\n    @add_obj(c, (yA[t, 1] - ybar)^2 for t = 0:T)\n    @add_obj(c, (u[t] - ubar)^2 for t = 0:T)\n\n    @add_con(c, xA[0, i] - xA0 for (i, xA0) in xA0s)\n    @add_con(\n        c,\n        (xA[t, 0] - xA[t-1, 0]) / dt - (1 / Ac) * (yA[t, 1] - xA[t, 0]) for t = 1:T\n    )\n    @add_con(\n        c,\n        (xA[t, i] - xA[t-1, i]) / dt -\n        (1 / At) * (u[t] * D * (yA[t, i-1] - xA[t, i]) - V[t] * (yA[t, i] - yA[t, i+1])) for\n        (t, i) in itr0\n    )\n    @add_con(\n        c,\n        (xA[t, FT] - xA[t-1, FT]) / dt -\n        (1 / At) * (\n            F * xAf + u[t] * D * xA[t, FT-1] - L2[t] * xA[t, FT] -\n            V[t] * (yA[t, FT] - yA[t, FT+1])\n        ) for t = 1:T\n    )\n    @add_con(\n        c,\n        (xA[t, i] - xA[t-1, i]) / dt -\n        (1 / At) * (L2[t] * (yA[t, i-1] - xA[t, i]) - V[t] * (yA[t, i] - yA[t, i+1])) for\n        (t, i) in itr1\n    )\n    @add_con(\n        c,\n        (xA[t, NT+1] - xA[t-1, NT+1]) / dt -\n        (1 / Ar) * (L2[t] * xA[t, NT] - (F - D) * xA[t, NT+1] - V[t] * yA[t, NT+1]) for\n        t = 1:T\n    )\n    @add_con(c, V[t] - u[t] * D - D for t = 0:T)\n    @add_con(c, L2[t] - u[t] * D - F for t = 0:T)\n    @add_con(\n        c,\n        yA[t, i] * (1 - xA[t, i]) - alpha * xA[t, i] * (1 - yA[t, i]) for (t, i) in itr2\n    )\n\n    return ExaModel(c)\nend\n\ndistillation_column_model (generic function with 2 methods)","category":"section"},{"location":"distillation/#Model-with-Lifted-Subexpressions","page":"Example: Distillation Column","title":"Model with Lifted Subexpressions","text":"Uses subexpressions for time derivatives and vapor differences. This adds auxiliary variables and constraints but makes the model more readable.\n\nfunction distillation_column_model_with_subexpr(T = 3; backend = nothing)\n\n    NT = 30\n    FT = 17\n    Ac = 0.5\n    At = 0.25\n    Ar = 1.0\n    D = 0.2\n    F = 0.4\n    ybar = 0.8958\n    ubar = 2.0\n    alpha = 1.6\n    dt = 10 / T\n    xAf = 0.5\n    xA0s = ExaModels.convert_array([(i, 0.5) for i in 0:(NT + 1)], backend)\n\n    c = ExaCore(; backend, concrete = Val(true))\n\n    # Decision variables\n    @add_var(c, xA, 0:T, 0:(NT + 1); start = 0.5)\n    @add_var(c, yA, 0:T, 0:(NT + 1); start = 0.5)\n    @add_var(c, u, 0:T; start = 1.0)\n    @add_var(c, V, 0:T; start = 1.0)\n    @add_var(c, L2, 0:T; start = 1.0)\n\n    # Subexpressions - define common terms once\n    @add_expr(c, dxA, (xA[t, i] - xA[t - 1, i]) / dt for t in 1:T, i in 0:(NT + 1))\n    @add_expr(c, dyA, yA[t, i] - yA[t, i + 1] for t in 0:T, i in 0:NT)\n\n    # Objectives\n    @add_obj(c, (yA[t, 1] - ybar)^2 for t in 0:T)\n    @add_obj(c, (u[t] - ubar)^2 for t in 0:T)\n\n    # Initial conditions\n    @add_con(c, xA[0, i] - xA0 for (i, xA0) in xA0s)\n\n    # Condenser - now using dxA subexpression\n    @add_con(c, dxA[t, 0] - (1 / Ac) * (yA[t, 1] - xA[t, 0]) for t in 1:T)\n\n    # Rectifying section - cleaner with dxA and dyA\n    itr_rect = ExaModels.convert_array(collect(Iterators.product(1:T, 1:(FT - 1))), backend)\n    @add_con(c, dxA[t, i] - (1 / At) * (u[t] * D * (yA[t, i - 1] - xA[t, i]) - V[t] * dyA[t, i]) for (t, i) in itr_rect)\n\n    # Feed tray\n    @add_con(c, dxA[t, FT] - (1 / At) * (F * xAf + u[t] * D * xA[t, FT - 1] - L2[t] * xA[t, FT] - V[t] * dyA[t, FT]) for t in 1:T)\n\n    # Stripping section\n    itr_strip = ExaModels.convert_array(collect(Iterators.product(1:T, (FT + 1):NT)), backend)\n    @add_con(c, dxA[t, i] - (1 / At) * (L2[t] * (yA[t, i - 1] - xA[t, i]) - V[t] * dyA[t, i]) for (t, i) in itr_strip)\n\n    # Reboiler\n    @add_con(c, dxA[t, NT + 1] - (1 / Ar) * (L2[t] * xA[t, NT] - (F - D) * xA[t, NT + 1] - V[t] * yA[t, NT + 1]) for t in 1:T)\n\n    # Flow relationships\n    @add_con(c, V[t] - u[t] * D - D for t in 0:T)\n    @add_con(c, L2[t] - u[t] * D - F for t in 0:T)\n\n    # VLE\n    itr_vle = ExaModels.convert_array(collect(Iterators.product(0:T, 0:(NT + 1))), backend)\n    @add_con(c, yA[t, i] * (1 - xA[t, i]) - alpha * xA[t, i] * (1 - yA[t, i]) for (t, i) in itr_vle)\n\n    return ExaModel(c)\nend\n\ndistillation_column_model_with_subexpr (generic function with 2 methods)","category":"section"},{"location":"distillation/#Running-the-Models","page":"Example: Distillation Column","title":"Running the Models","text":"Let's compare both formulations and verify they converge to the same solution.\n\nT_val = 10\n\n10\n\nWithout subexpressions:\n\nm_orig = distillation_column_model(T_val)\nresult_orig = ipopt(m_orig; print_level = 0)\n\n\"Execution stats: first-order stationary\"\n\nWith subexpressions:\n\nm_subexpr = distillation_column_model_with_subexpr(T_val)\nresult_subexpr = ipopt(m_subexpr; print_level = 0)\n\n\"Execution stats: first-order stationary\"","category":"section"},{"location":"distillation/#Comparison-Results","page":"Example: Distillation Column","title":"Comparison Results","text":"println(\"=\"^62)\nprintln(\"Distillation Column Model Comparison (T=$T_val)\")\nprintln(\"=\"^62)\nprintln()\nprintln(\"| Model               | Variables | Constraints | Iterations | Objective |\")\nprintln(\"|---------------------|-----------|-------------|------------|-----------|\")\nprintln(\"| Original            | $(lpad(m_orig.meta.nvar, 9)) | $(lpad(m_orig.meta.ncon, 11)) | $(lpad(result_orig.iter, 10)) | $(round(result_orig.objective, digits = 6)) |\")\nprintln(\"| With subexpressions | $(lpad(m_subexpr.meta.nvar, 9)) | $(lpad(m_subexpr.meta.ncon, 11)) | $(lpad(result_subexpr.iter, 10)) | $(round(result_subexpr.objective, digits = 6)) |\")\nprintln()\n\n==============================================================\nDistillation Column Model Comparison (T=10)\n==============================================================\n\n| Model               | Variables | Constraints | Iterations | Objective |\n|---------------------|-----------|-------------|------------|-----------|\n| Original            |       737 |         726 |          7 | 0.15107 |\n| With subexpressions |       737 |         726 |          7 | 0.15107 |\n\n\n\nBoth formulations are equivalent NLPs and converge to the same solution:\n\nprintln(\"Same objective: \", isapprox(result_orig.objective, result_subexpr.objective, rtol = 1.0e-4))\n\nSame objective: true\n\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"parameters/#parameters","page":"Parameters","title":"Parameters","text":"Parameters act like fixed variables. Internally, ExaModels keeps track of where parameters appear in the model, making it possible to efficiently modify their value without rebuilding the entire model.","category":"section"},{"location":"parameters/#Creating-Parametric-Models","page":"Parameters","title":"Creating Parametric Models","text":"Let's modify the example in Getting Started to use parameters. Suppose we want to make the penalty coefficient in the objective function adjustable:\n\nFirst, let's create a core:\n\nusing ExaModels, NLPModelsIpopt\nc_param = ExaCore(concrete = Val(true))\n\nAn ExaCore\n\n  Float type: ...................... Float64\n  Array type: ...................... Vector{Float64}\n  Backend: ......................... Nothing\n\n  number of objective patterns: .... 0\n  number of constraint patterns: ... 0\n\n\nAdding parameters is very similar to adding variables – just pass a vector of values denoting the initial values.\n\n@add_par(c_param, θ, [100.0, 1.0])  # [penalty_coeff, offset]\n\nParameter\n\n  θ ∈ R^{2}\n\n\nDefine the variables as before:\n\nN = 10\n@add_var(c_param, x_p, N; start = (mod(i, 2) == 1 ? -1.2 : 1.0 for i = 1:N))\n\nVariable\n\n  x ∈ R^{10}\n\n\nNow we can use the parameters in our objective function just like variables:\n\n@add_obj(c_param, θ[1] * (x_p[i-1]^2 - x_p[i])^2 + (x_p[i-1] - θ[2])^2 for i = 2:N)\n\nObjective\n\n  min (...) + ∑_{p ∈ P} f(x,θ,p)\n\n  where |P| = 9\n\n\nAdd the same constraints as before:\n\n@add_con(\n    c_param,\n    3x_p[i+1]^3 + 2 * x_p[i+2] - 5 +\n    sin(x_p[i+1] - x_p[i+2])sin(x_p[i+1] + x_p[i+2]) +\n    4x_p[i+1] - x_p[i]exp(x_p[i] - x_p[i+1]) - 3 for i = 1:(N-2)\n)\n\nConstraint\n\n  s.t. (...)\n       g♭ ≤ [g(x,θ,p)]_{p ∈ P} ≤ g♯\n\n  where |P| = 8\n\n\nCreate the model as before:\n\nm_param = ExaModel(c_param)\n\nAn ExaModel{Float64, Vector{Float64}, ...}\n\n  Problem name: Generic\n   All variables: ████████████████████ 10     All constraints: ████████████████████ 8     \n            free: ████████████████████ 10                free: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n           lower: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                lower: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n           upper: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                upper: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n         low/upp: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0              low/upp: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n           fixed: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                fixed: ████████████████████ 8     \n          infeas: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0               infeas: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n            nnzh: (-36.36% sparsity)   75              linear: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n                                                    nonlinear: ████████████████████ 8     \n                                                         nnzj: ( 70.00% sparsity)   24    \n                                                     lin_nnzj: (------% sparsity)         \n                                                     nln_nnzj: ( 70.00% sparsity)   24    \n\n\n\nSolve with original parameters:\n\nresult1 = ipopt(m_param)\nprintln(\"Original objective: $(result1.objective)\")\n\nThis is Ipopt version 3.14.19, running with linear solver MUMPS 5.8.2.\n\nNumber of nonzeros in equality constraint Jacobian...:       24\nNumber of nonzeros in inequality constraint Jacobian.:        0\nNumber of nonzeros in Lagrangian Hessian.............:       75\n\nTotal number of variables............................:       10\n                     variables with only lower bounds:        0\n                variables with lower and upper bounds:        0\n                     variables with only upper bounds:        0\nTotal number of equality constraints.................:        8\nTotal number of inequality constraints...............:        0\n        inequality constraints with only lower bounds:        0\n   inequality constraints with lower and upper bounds:        0\n        inequality constraints with only upper bounds:        0\n\niter    objective    inf_pr   inf_du lg(mu)  ||d||  lg(rg) alpha_du alpha_pr  ls\n   0  2.0570000e+03 2.48e+01 2.73e+01  -1.0 0.00e+00    -  0.00e+00 0.00e+00   0\n   1  1.0953147e+03 1.49e+01 8.27e+01  -1.0 2.20e+00    -  1.00e+00 1.00e+00f  1\n   2  3.2865521e+02 4.28e+00 1.36e+02  -1.0 1.43e+00    -  1.00e+00 1.00e+00f  1\n   3  1.3995370e+01 3.09e-01 2.18e+01  -1.0 5.63e-01    -  1.00e+00 1.00e+00f  1\n   4  6.2325715e+00 1.73e-02 8.47e-01  -1.0 2.10e-01    -  1.00e+00 1.00e+00f  1\n   5  6.2324586e+00 1.15e-05 8.16e-04  -1.7 3.35e-03    -  1.00e+00 1.00e+00h  1\n   6  6.2324586e+00 8.35e-12 7.97e-10  -5.7 2.00e-06    -  1.00e+00 1.00e+00h  1\n\nNumber of Iterations....: 6\n\n                                   (scaled)                 (unscaled)\nObjective...............:   7.8692659500473017e-01    6.2324586324374636e+00\nDual infeasibility......:   7.9746955363607132e-10    6.3159588647976857e-09\nConstraint violation....:   8.3546503049092280e-12    8.3546503049092280e-12\nVariable bound violation:   0.0000000000000000e+00    0.0000000000000000e+00\nComplementarity.........:   0.0000000000000000e+00    0.0000000000000000e+00\nOverall NLP error.......:   7.9746955363607132e-10    6.3159588647976857e-09\n\n\nNumber of objective function evaluations             = 7\nNumber of objective gradient evaluations             = 7\nNumber of equality constraint evaluations            = 7\nNumber of inequality constraint evaluations          = 0\nNumber of equality constraint Jacobian evaluations   = 7\nNumber of inequality constraint Jacobian evaluations = 0\nNumber of Lagrangian Hessian evaluations             = 6\nTotal seconds in IPOPT                               = 0.372\n\nEXIT: Optimal Solution Found.\nOriginal objective: 6.232458632437464\n\n\nNow change the penalty coefficient and solve again:\n\nset_parameter!(c_param, θ, [200.0, 1.0])  # Double the penalty coefficient\nresult2 = ipopt(m_param)\nprintln(\"Modified penalty objective: $(result2.objective)\")\n\nThis is Ipopt version 3.14.19, running with linear solver MUMPS 5.8.2.\n\nNumber of nonzeros in equality constraint Jacobian...:       24\nNumber of nonzeros in inequality constraint Jacobian.:        0\nNumber of nonzeros in Lagrangian Hessian.............:       75\n\nTotal number of variables............................:       10\n                     variables with only lower bounds:        0\n                variables with lower and upper bounds:        0\n                     variables with only upper bounds:        0\nTotal number of equality constraints.................:        8\nTotal number of inequality constraints...............:        0\n        inequality constraints with only lower bounds:        0\n   inequality constraints with lower and upper bounds:        0\n        inequality constraints with only upper bounds:        0\n\niter    objective    inf_pr   inf_du lg(mu)  ||d||  lg(rg) alpha_du alpha_pr  ls\n   0  4.0898000e+03 2.48e+01 2.70e+01  -1.0 0.00e+00    -  0.00e+00 0.00e+00   0\n   1  2.1810502e+03 1.49e+01 8.27e+01  -1.0 2.20e+00    -  1.00e+00 1.00e+00f  1\n   2  6.5137192e+02 4.27e+00 1.36e+02  -1.0 1.43e+00    -  1.00e+00 1.00e+00f  1\n   3  2.4064340e+01 3.08e-01 2.18e+01  -1.0 5.62e-01    -  1.00e+00 1.00e+00f  1\n   4  8.6476680e+00 1.72e-02 8.45e-01  -1.0 2.10e-01    -  1.00e+00 1.00e+00f  1\n   5  8.6474398e+00 1.15e-05 8.07e-04  -1.7 3.39e-03    -  1.00e+00 1.00e+00h  1\n   6  8.6474398e+00 8.42e-12 7.91e-10  -5.7 2.03e-06    -  1.00e+00 1.00e+00h  1\n\nNumber of Iterations....: 6\n\n                                   (scaled)                 (unscaled)\nObjective...............:   5.4592422674820063e-01    8.6474397516914987e+00\nDual infeasibility......:   7.9051456536755353e-10    1.2521750715422049e-08\nConstraint violation....:   8.4190432403374871e-12    8.4190432403374871e-12\nVariable bound violation:   0.0000000000000000e+00    0.0000000000000000e+00\nComplementarity.........:   0.0000000000000000e+00    0.0000000000000000e+00\nOverall NLP error.......:   7.9051456536755353e-10    1.2521750715422049e-08\n\n\nNumber of objective function evaluations             = 7\nNumber of objective gradient evaluations             = 7\nNumber of equality constraint evaluations            = 7\nNumber of inequality constraint evaluations          = 0\nNumber of equality constraint Jacobian evaluations   = 7\nNumber of inequality constraint Jacobian evaluations = 0\nNumber of Lagrangian Hessian evaluations             = 6\nTotal seconds in IPOPT                               = 0.002\n\nEXIT: Optimal Solution Found.\nModified penalty objective: 8.647439751691499\n\n\nTry a different offset parameter:\n\nset_parameter!(c_param, θ, [200.0, 0.5])  # Change the offset in the objective\nresult3 = ipopt(m_param)\nprintln(\"Modified offset objective: $(result3.objective)\")\n\nThis is Ipopt version 3.14.19, running with linear solver MUMPS 5.8.2.\n\nNumber of nonzeros in equality constraint Jacobian...:       24\nNumber of nonzeros in inequality constraint Jacobian.:        0\nNumber of nonzeros in Lagrangian Hessian.............:       75\n\nTotal number of variables............................:       10\n                     variables with only lower bounds:        0\n                variables with lower and upper bounds:        0\n                     variables with only upper bounds:        0\nTotal number of equality constraints.................:        8\nTotal number of inequality constraints...............:        0\n        inequality constraints with only lower bounds:        0\n   inequality constraints with lower and upper bounds:        0\n        inequality constraints with only upper bounds:        0\n\niter    objective    inf_pr   inf_du lg(mu)  ||d||  lg(rg) alpha_du alpha_pr  ls\n   0  4.0810500e+03 2.48e+01 2.69e+01  -1.0 0.00e+00    -  0.00e+00 0.00e+00   0\n   1  2.1767809e+03 1.49e+01 8.26e+01  -1.0 2.20e+00    -  1.00e+00 1.00e+00f  1\n   2  6.5050886e+02 4.27e+00 1.36e+02  -1.0 1.43e+00    -  1.00e+00 1.00e+00f  1\n   3  2.4276149e+01 3.07e-01 2.18e+01  -1.0 5.61e-01    -  1.00e+00 1.00e+00f  1\n   4  8.8465512e+00 1.72e-02 8.43e-01  -1.0 2.09e-01    -  1.00e+00 1.00e+00f  1\n   5  8.8451636e+00 1.15e-05 8.04e-04  -1.7 3.40e-03    -  1.00e+00 1.00e+00h  1\n   6  8.8451630e+00 8.47e-12 7.88e-10  -5.7 2.05e-06    -  1.00e+00 1.00e+00h  1\n\nNumber of Iterations....: 6\n\n                                   (scaled)                 (unscaled)\nObjective...............:   5.5805444714793528e-01    8.8451629872947741e+00\nDual infeasibility......:   7.8812124187921384e-10    1.2491721683785540e-08\nConstraint violation....:   8.4678930534209940e-12    8.4678930534209940e-12\nVariable bound violation:   0.0000000000000000e+00    0.0000000000000000e+00\nComplementarity.........:   0.0000000000000000e+00    0.0000000000000000e+00\nOverall NLP error.......:   7.8812124187921384e-10    1.2491721683785540e-08\n\n\nNumber of objective function evaluations             = 7\nNumber of objective gradient evaluations             = 7\nNumber of equality constraint evaluations            = 7\nNumber of inequality constraint evaluations          = 0\nNumber of equality constraint Jacobian evaluations   = 7\nNumber of inequality constraint Jacobian evaluations = 0\nNumber of Lagrangian Hessian evaluations             = 6\nTotal seconds in IPOPT                               = 0.001\n\nEXIT: Optimal Solution Found.\nModified offset objective: 8.845162987294774\n\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"opf/#opf","page":"Example: Optimal Power Flow","title":"Example: Optimal Power Flow","text":"using ExaModels\n\nfunction parse_ac_power_data(filename)\n    data = PowerModels.parse_file(filename)\n    PowerModels.standardize_cost_terms!(data, order = 2)\n    PowerModels.calc_thermal_limits!(data)\n    ref = PowerModels.build_ref(data)[:it][:pm][:nw][0]\n\n    arcdict = Dict(a => k for (k, a) in enumerate(ref[:arcs]))\n    busdict = Dict(k => i for (i, (k, v)) in enumerate(ref[:bus]))\n    gendict = Dict(k => i for (i, (k, v)) in enumerate(ref[:gen]))\n    branchdict = Dict(k => i for (i, (k, v)) in enumerate(ref[:branch]))\n\n    return (\n        bus = [\n            begin\n                bus_loads = [ref[:load][l] for l in ref[:bus_loads][k]]\n                bus_shunts = [ref[:shunt][s] for s in ref[:bus_shunts][k]]\n                pd = sum(load[\"pd\"] for load in bus_loads; init = 0.0)\n                gs = sum(shunt[\"gs\"] for shunt in bus_shunts; init = 0.0)\n                qd = sum(load[\"qd\"] for load in bus_loads; init = 0.0)\n                bs = sum(shunt[\"bs\"] for shunt in bus_shunts; init = 0.0)\n                (i = busdict[k], pd = pd, gs = gs, qd = qd, bs = bs)\n            end for (k, v) in ref[:bus]\n        ],\n        gen = [\n            (\n                i = gendict[k],\n                cost1 = v[\"cost\"][1],\n                cost2 = v[\"cost\"][2],\n                cost3 = v[\"cost\"][3],\n                bus = busdict[v[\"gen_bus\"]],\n            ) for (k, v) in ref[:gen]\n        ],\n        arc = [\n            (i = k, rate_a = ref[:branch][l][\"rate_a\"], bus = busdict[i]) for\n            (k, (l, i, j)) in enumerate(ref[:arcs])\n        ],\n        branch = [\n            begin\n                f_idx = arcdict[i, branch[\"f_bus\"], branch[\"t_bus\"]]\n                t_idx = arcdict[i, branch[\"t_bus\"], branch[\"f_bus\"]]\n                g, b = PowerModels.calc_branch_y(branch)\n                tr, ti = PowerModels.calc_branch_t(branch)\n                ttm = tr^2 + ti^2\n                g_fr = branch[\"g_fr\"]\n                b_fr = branch[\"b_fr\"]\n                g_to = branch[\"g_to\"]\n                b_to = branch[\"b_to\"]\n                c1 = (-g * tr - b * ti) / ttm\n                c2 = (-b * tr + g * ti) / ttm\n                c3 = (-g * tr + b * ti) / ttm\n                c4 = (-b * tr - g * ti) / ttm\n                c5 = (g + g_fr) / ttm\n                c6 = (b + b_fr) / ttm\n                c7 = (g + g_to)\n                c8 = (b + b_to)\n                (\n                    i = branchdict[i],\n                    j = 1,\n                    f_idx = f_idx,\n                    t_idx = t_idx,\n                    f_bus = busdict[branch[\"f_bus\"]],\n                    t_bus = busdict[branch[\"t_bus\"]],\n                    c1 = c1,\n                    c2 = c2,\n                    c3 = c3,\n                    c4 = c4,\n                    c5 = c5,\n                    c6 = c6,\n                    c7 = c7,\n                    c8 = c8,\n                    rate_a_sq = branch[\"rate_a\"]^2,\n                )\n            end for (i, branch) in ref[:branch]\n        ],\n        ref_buses = [busdict[i] for (i, k) in ref[:ref_buses]],\n        vmax = [v[\"vmax\"] for (k, v) in ref[:bus]],\n        vmin = [v[\"vmin\"] for (k, v) in ref[:bus]],\n        pmax = [v[\"pmax\"] for (k, v) in ref[:gen]],\n        pmin = [v[\"pmin\"] for (k, v) in ref[:gen]],\n        qmax = [v[\"qmax\"] for (k, v) in ref[:gen]],\n        qmin = [v[\"qmin\"] for (k, v) in ref[:gen]],\n        rate_a = [ref[:branch][l][\"rate_a\"] for (k, (l, i, j)) in enumerate(ref[:arcs])],\n        angmax = [b[\"angmax\"] for (i, b) in ref[:branch]],\n        angmin = [b[\"angmin\"] for (i, b) in ref[:branch]],\n    )\nend\n\nconvert_data(data::N, backend) where {names,N<:NamedTuple{names}} =\n    NamedTuple{names}(ExaModels.convert_array(d, backend) for d in data)\n\nparse_ac_power_data(filename, backend) =\n    convert_data(parse_ac_power_data(filename), backend)\n\nfunction ac_power_model(filename; backend = nothing, T = Float64)\n\n    data = parse_ac_power_data(filename, backend)\n\n    w = ExaCore(T; backend = backend, concrete = Val(true))\n\n    @add_var(w, va, length(data.bus);)\n\n    @add_var(\n        w,\n        vm,\n        length(data.bus);\n        start = fill!(similar(data.bus, Float64), 1.0),\n        lvar = data.vmin,\n        uvar = data.vmax,\n    )\n    @add_var(w, pg, length(data.gen); lvar = data.pmin, uvar = data.pmax)\n\n    @add_var(w, qg, length(data.gen); lvar = data.qmin, uvar = data.qmax)\n\n    @add_var(w, p, length(data.arc); lvar = -data.rate_a, uvar = data.rate_a)\n\n    @add_var(w, q, length(data.arc); lvar = -data.rate_a, uvar = data.rate_a)\n\n    o = @add_obj(w, g.cost1 * pg[g.i]^2 + g.cost2 * pg[g.i] + g.cost3 for g in data.gen)\n\n    @add_con(w, c1, va[i] for i in data.ref_buses)\n\n    @add_con(\n        w,\n        c2,\n        p[b.f_idx] - b.c5 * vm[b.f_bus]^2 -\n        b.c3 * (vm[b.f_bus] * vm[b.t_bus] * cos(va[b.f_bus] - va[b.t_bus])) -\n        b.c4 * (vm[b.f_bus] * vm[b.t_bus] * sin(va[b.f_bus] - va[b.t_bus])) for\n        b in data.branch\n    )\n\n    @add_con(\n        w,\n        c3,\n        q[b.f_idx] +\n        b.c6 * vm[b.f_bus]^2 +\n        b.c4 * (vm[b.f_bus] * vm[b.t_bus] * cos(va[b.f_bus] - va[b.t_bus])) -\n        b.c3 * (vm[b.f_bus] * vm[b.t_bus] * sin(va[b.f_bus] - va[b.t_bus])) for\n        b in data.branch\n    )\n\n    @add_con(\n        w,\n        c4,\n        p[b.t_idx] - b.c7 * vm[b.t_bus]^2 -\n        b.c1 * (vm[b.t_bus] * vm[b.f_bus] * cos(va[b.t_bus] - va[b.f_bus])) -\n        b.c2 * (vm[b.t_bus] * vm[b.f_bus] * sin(va[b.t_bus] - va[b.f_bus])) for\n        b in data.branch\n    )\n\n    @add_con(\n        w,\n        c5,\n        q[b.t_idx] +\n        b.c8 * vm[b.t_bus]^2 +\n        b.c2 * (vm[b.t_bus] * vm[b.f_bus] * cos(va[b.t_bus] - va[b.f_bus])) -\n        b.c1 * (vm[b.t_bus] * vm[b.f_bus] * sin(va[b.t_bus] - va[b.f_bus])) for\n        b in data.branch\n    )\n\n    @add_con(\n        w,\n        c6,\n        va[b.f_bus] - va[b.t_bus] for b in data.branch;\n        lcon = data.angmin,\n        ucon = data.angmax,\n    )\n    @add_con(\n        w,\n        c7,\n        p[b.f_idx]^2 + q[b.f_idx]^2 - b.rate_a_sq for b in data.branch;\n        lcon = fill!(similar(data.branch, Float64, length(data.branch)), -Inf),\n    )\n    @add_con(\n        w,\n        c8,\n        p[b.t_idx]^2 + q[b.t_idx]^2 - b.rate_a_sq for b in data.branch;\n        lcon = fill!(similar(data.branch, Float64, length(data.branch)), -Inf),\n    )\n\n    @add_con(w, c9, b.pd + b.gs * vm[b.i]^2 for b in data.bus)\n\n    @add_con(w, c10, b.qd - b.bs * vm[b.i]^2 for b in data.bus)\n\n    c11 = @add_con!(w, c9, a.bus => p[a.i] for a in data.arc)\n    c12 = @add_con!(w, c10, a.bus => q[a.i] for a in data.arc)\n\n    c13 = @add_con!(w, c9, g.bus => -pg[g.i] for g in data.gen)\n    c14 = @add_con!(w, c10, g.bus => -qg[g.i] for g in data.gen)\n\n    return ExaModel(w)\n\nend\n\nac_power_model (generic function with 1 method)\n\nWe first download the case file.\n\nusing Downloads\n\ncase = tempname() * \".m\"\n\nDownloads.download(\n    \"https://raw.githubusercontent.com/power-grid-lib/pglib-opf/dc6be4b2f85ca0e776952ec22cbd4c22396ea5a3/pglib_opf_case3_lmbd.m\",\n    case,\n)\n\n\"/tmp/jl_6pW1ANw7KZ.m\"\n\nThen, we can model/sovle the problem.\n\nusing PowerModels, ExaModels, NLPModelsIpopt\n\nm = ac_power_model(case)\nipopt(m)\n\n\"Execution stats: first-order stationary\"\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"performance/#Performance-Tips","page":"Performance Tips","title":"Performance Tips","text":"","category":"section"},{"location":"performance/#Use-a-function-to-create-a-model","page":"Performance Tips","title":"Use a function to create a model","text":"It is always better to use functions to create ExaModels. This in this way, the functions used for specifing objective/constraint functions are not recreated over all over, and thus, we can take advantage of the previously compiled model creation code. Let's consider the following example.\n\nusing ExaModels\n\nt = @elapsed begin\n    c = ExaCore(concrete = Val(true))\n    N = 10\n    @add_var(c, x, N; start = (mod(i, 2) == 1 ? -1.2 : 1.0 for i = 1:N))\n    @add_obj(c, 100 * (x[i-1]^2 - x[i])^2 + (x[i-1] - 1)^2 for i = 2:N)\n    @add_con(\n        c,\n        3x[i+1]^3 + 2 * x[i+2] - 5 + sin(x[i+1] - x[i+2])sin(x[i+1] + x[i+2]) + 4x[i+1] - x[i]exp(x[i] - x[i+1]) - 3 for i = 1:(N-2)\n    )\n    m = ExaModel(c)\nend\n\nprintln(\"$t seconds elapsed\")\n\n0.144191077 seconds elapsed\n\n\nEven at the second call,\n\nt = @elapsed begin\n    c = ExaCore(concrete = Val(true))\n    N = 10\n    @add_var(c, x, N; start = (mod(i, 2) == 1 ? -1.2 : 1.0 for i = 1:N))\n    @add_obj(c, 100 * (x[i-1]^2 - x[i])^2 + (x[i-1] - 1)^2 for i = 2:N)\n    @add_con(\n        c,\n        3x[i+1]^3 + 2 * x[i+2] - 5 + sin(x[i+1] - x[i+2])sin(x[i+1] + x[i+2]) + 4x[i+1] - x[i]exp(x[i] - x[i+1]) - 3 for i = 1:(N-2)\n    )\n    m = ExaModel(c)\nend\n\nprintln(\"$t seconds elapsed\")\n\n0.115074508 seconds elapsed\n\n\nthe model creation time can be slightly reduced but the compilation time is still quite significant.\n\nBut instead, if you create a function, we can significantly reduce the model creation time.\n\nfunction luksan_vlcek_model(N)\n    c = ExaCore(concrete = Val(true))\n    @add_var(c, x, N; start = (mod(i, 2) == 1 ? -1.2 : 1.0 for i = 1:N))\n    @add_obj(c, 100 * (x[i-1]^2 - x[i])^2 + (x[i-1] - 1)^2 for i = 2:N)\n    @add_con(\n        c,\n        3x[i+1]^3 + 2 * x[i+2] - 5 + sin(x[i+1] - x[i+2])sin(x[i+1] + x[i+2]) + 4x[i+1] -\n        x[i]exp(x[i] - x[i+1]) - 3 for i = 1:(N-2)\n    )\n    m = ExaModel(c)\nend\n\nt = @elapsed luksan_vlcek_model(N)\nprintln(\"$t seconds elapsed\")\n\n0.431142624 seconds elapsed\n\n\nt = @elapsed luksan_vlcek_model(N)\nprintln(\"$t seconds elapsed\")\n\n4.416e-5 seconds elapsed\n\n\nSo, the model creation time can be essentially nothing. Thus, if you care about the model creation time, always make sure to write a function for creating the model, and do not directly create a model from the REPL.","category":"section"},{"location":"performance/#Make-sure-your-array's-eltype-is-concrete","page":"Performance Tips","title":"Make sure your array's eltype is concrete","text":"In order for ExaModels to run for loops over the array you provided without any overhead caused by type inference, the eltype of the data array should always be a concrete type. Furthermore, this is required if you want to run ExaModels on GPU accelerators.\n\nLet's take an example.\n\nusing ExaModels\n\nN = 1000\n\nfunction luksan_vlcek_model_concrete(N)\n    c = ExaCore(concrete = Val(true))\n\n    arr1 = Array(2:N)\n    arr2 = Array(1:(N-2))\n\n    @add_var(c, x, N; start = (mod(i, 2) == 1 ? -1.2 : 1.0 for i = 1:N))\n    @add_obj(c, 100 * (x[i-1]^2 - x[i])^2 + (x[i-1] - 1)^2 for i in arr1)\n    @add_con(\n        c,\n        3x[i+1]^3 + 2 * x[i+2] - 5 + sin(x[i+1] - x[i+2])sin(x[i+1] + x[i+2]) + 4x[i+1] -\n        x[i]exp(x[i] - x[i+1]) - 3 for i in arr2\n    )\n    m = ExaModel(c)\nend\n\nfunction luksan_vlcek_model_non_concrete(N)\n    c = ExaCore(concrete = Val(true))\n\n    arr1 = Array{Any}(2:N)\n    arr2 = Array{Any}(1:(N-2))\n\n    @add_var(c, x, N; start = (mod(i, 2) == 1 ? -1.2 : 1.0 for i = 1:N))\n    @add_obj(c, 100 * (x[i-1]^2 - x[i])^2 + (x[i-1] - 1)^2 for i in arr1)\n    @add_con(\n        c,\n        3x[i+1]^3 + 2 * x[i+2] - 5 + sin(x[i+1] - x[i+2])sin(x[i+1] + x[i+2]) + 4x[i+1] -\n        x[i]exp(x[i] - x[i+1]) - 3 for i in arr2\n    )\n    m = ExaModel(c)\nend\n\nluksan_vlcek_model_non_concrete (generic function with 1 method)\n\nHere, observe that\n\nisconcretetype(eltype(Array(2:N)))\n\ntrue\n\nisconcretetype(eltype(Array{Any}(2:N)))\n\nfalse\n\nAs you can see, the first array type has concrete eltypes, whereas the second array type has non concrete eltypes. Due to this, the array stored in the model created by luksan_vlcek_model_non_concrete will have non-concrete eltypes.\n\nNow let's compare the performance. We will use the following benchmark function here.\n\nusing NLPModels\n\nfunction benchmark_callbacks(m; N = 100)\n    nvar = m.meta.nvar\n    ncon = m.meta.ncon\n    nnzj = m.meta.nnzj\n    nnzh = m.meta.nnzh\n\n    x = copy(m.meta.x0)\n    y = similar(m.meta.x0, ncon)\n    c = similar(m.meta.x0, ncon)\n    g = similar(m.meta.x0, nvar)\n    jac = similar(m.meta.x0, nnzj)\n    hess = similar(m.meta.x0, nnzh)\n    jrows = similar(m.meta.x0, Int, nnzj)\n    jcols = similar(m.meta.x0, Int, nnzj)\n    hrows = similar(m.meta.x0, Int, nnzh)\n    hcols = similar(m.meta.x0, Int, nnzh)\n\n    GC.enable(false)\n\n    NLPModels.obj(m, x) # to compile\n\n    tobj = (1 / N) * @elapsed for t = 1:N\n        NLPModels.obj(m, x)\n    end\n\n    NLPModels.cons!(m, x, c) # to compile\n    tcon = (1 / N) * @elapsed for t = 1:N\n        NLPModels.cons!(m, x, c)\n    end\n\n    NLPModels.grad!(m, x, g) # to compile\n    tgrad = (1 / N) * @elapsed for t = 1:N\n        NLPModels.grad!(m, x, g)\n    end\n\n    NLPModels.jac_coord!(m, x, jac) # to compile\n    tjac = (1 / N) * @elapsed for t = 1:N\n        NLPModels.jac_coord!(m, x, jac)\n    end\n\n    NLPModels.hess_coord!(m, x, y, hess) # to compile\n    thess = (1 / N) * @elapsed for t = 1:N\n        NLPModels.hess_coord!(m, x, y, hess)\n    end\n\n    NLPModels.jac_structure!(m, jrows, jcols) # to compile\n    tjacs = (1 / N) * @elapsed for t = 1:N\n        NLPModels.jac_structure!(m, jrows, jcols)\n    end\n\n    NLPModels.hess_structure!(m, hrows, hcols) # to compile\n    thesss = (1 / N) * @elapsed for t = 1:N\n        NLPModels.hess_structure!(m, hrows, hcols)\n    end\n\n    GC.enable(true)\n\n    return (\n        tobj = tobj,\n        tcon = tcon,\n        tgrad = tgrad,\n        tjac = tjac,\n        thess = thess,\n        tjacs = tjacs,\n        thesss = thesss,\n    )\nend\n\nbenchmark_callbacks (generic function with 1 method)\n\nThe performance comparison is here:\n\nm1 = luksan_vlcek_model_concrete(N)\nm2 = luksan_vlcek_model_non_concrete(N)\n\nbenchmark_callbacks(m1)\n\n(tobj = 2.1374100000000003e-6, tcon = 2.541519e-5, tgrad = 5.72437e-6, tjac = 5.438251e-5, thess = 0.00037628958, tjacs = 1.168707e-5, thesss = 1.863903e-5)\n\nbenchmark_callbacks(m2)\n\n(tobj = 5.8877290000000006e-5, tcon = 0.00013296031, tgrad = 7.54763e-5, tjac = 0.00045599546, thess = 0.00097932615, tjacs = 0.00044071766, thesss = 0.00070130964)\n\nAs can be seen here, having concrete eltype dramatically improves the performance. This is because when all the data arrays' eltypes are concrete, the AD evaluations can be performed without any type inferernce, and this should be as fast as highly optimized C/C++/Fortran code.\n\nWhen you're using GPU accelerators, the eltype of the array should always be concrete. In fact, non-concrete etlype will already cause an error when creating the array. For example,\n\nusing CUDA\n\ntry\n    arr1 = CuArray(Array{Any}(2:N))\ncatch e\n    showerror(stdout, e)\nend\n\nCuArray only supports element types that are allocated inline.\nAny is not allocated inline\n\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"quad/#quad","page":"Example: Quadrotor","title":"Example: Quadrotor","text":"using ExaModels, NLPModelsIpopt\n\nfunction quadrotor_model(N = 3; backend = nothing)\n\n    n = 9\n    p = 4\n    d(i, j, N) =\n        (j == 1 ? 1 * sin(2 * pi / N * i) : 0.0) +\n        (j == 3 ? 2 * sin(4 * pi / N * i) : 0.0) +\n        (j == 5 ? 2 * i / N : 0.0)\n    dt = 1/N\n    R = fill(1 / 10, 4)\n    Q = [1, 0, 1, 0, 1, 0, 1, 1, 1]\n    Qf = [1, 0, 1, 0, 1, 0, 1, 1, 1] / dt\n\n    x0s = [(i, 0.0) for i = 1:n]\n    itr0 = [(i, j, R[j]) for (i, j) in Base.product(1:N, 1:p)]\n    itr1 = [(i, j, Q[j], d(i, j, N)) for (i, j) in Base.product(1:N, 1:n)]\n    itr2 = [(j, Qf[j], d(N + 1, j, N)) for j = 1:n]\n\n    c = ExaCore(; backend = backend, concrete = Val(true))\n\n    @add_var(c, x, 1:(N+1), 1:n)\n    @add_var(c, u, 1:N, 1:p)\n\n    @add_con(c, x[1, i] - x0 for (i, x0) in x0s)\n    @add_con(c, -x[i+1, 1] + x[i, 1] + (x[i, 2]) * dt for i = 1:N)\n    @add_con(\n        c,\n        -x[i+1, 2] +\n        x[i, 2] +\n        (\n            u[i, 1] * cos(x[i, 7]) * sin(x[i, 8]) * cos(x[i, 9]) +\n            u[i, 1] * sin(x[i, 7]) * sin(x[i, 9])\n        ) * dt for i = 1:N\n    )\n    @add_con(c, -x[i+1, 3] + x[i, 3] + (x[i, 4]) * dt for i = 1:N)\n    @add_con(\n        c,\n        -x[i+1, 4] +\n        x[i, 4] +\n        (\n            u[i, 1] * cos(x[i, 7]) * sin(x[i, 8]) * sin(x[i, 9]) -\n            u[i, 1] * sin(x[i, 7]) * cos(x[i, 9])\n        ) * dt for i = 1:N\n    )\n    @add_con(c, -x[i+1, 5] + x[i, 5] + (x[i, 6]) * dt for i = 1:N)\n    @add_con(\n        c,\n        -x[i+1, 6] + x[i, 6] + (u[i, 1] * cos(x[i, 7]) * cos(x[i, 8]) - 9.8) * dt for\n        i = 1:N\n    )\n    @add_con(\n        c,\n        -x[i+1, 7] +\n        x[i, 7] +\n        (u[i, 2] * cos(x[i, 7]) / cos(x[i, 8]) + u[i, 3] * sin(x[i, 7]) / cos(x[i, 8])) * dt\n        for i = 1:N\n    )\n    @add_con(\n        c,\n        -x[i+1, 8] + x[i, 8] + (-u[i, 2] * sin(x[i, 7]) + u[i, 3] * cos(x[i, 7])) * dt for\n        i = 1:N\n    )\n    @add_con(\n        c,\n        -x[i+1, 9] +\n        x[i, 9] +\n        (\n            u[i, 2] * cos(x[i, 7]) * tan(x[i, 8]) +\n            u[i, 3] * sin(x[i, 7]) * tan(x[i, 8]) +\n            u[i, 4]\n        ) * dt for i = 1:N\n    )\n\n    @add_obj(c, 0.5 * R * (u[i, j]^2) for (i, j, R) in itr0)\n    @add_obj(c, 0.5 * Q * (x[i, j] - d)^2 for (i, j, Q, d) in itr1)\n    @add_obj(c, 0.5 * Qf * (x[N+1, j] - d)^2 for (j, Qf, d) in itr2)\n\n    m = ExaModel(c)\n\nend\n\nquadrotor_model (generic function with 2 methods)\n\nm = quadrotor_model(100)\nresult = ipopt(m)\n\n\"Execution stats: first-order stationary\"\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"two_stage/#two_stage","page":"Two-Stage Optimization","title":"Two-Stage Optimization","text":"ExaModels supports two-stage optimization problems. This feature enables efficient modeling of optimization problems where decisions are made in two stages:\n\nDesign (first-stage) variables: Decisions made before uncertainty is revealed, shared across all scenarios\nRecourse (second-stage) variables: Scenario-specific decisions made after uncertainty is revealed\nScenarios: Each scenario has its own parameters θ that affect the objective and constraints\n\nusing ExaModels, NLPModelsIpopt\n\nDefine the problem dimensions and scenario parameters:\n\nns = 3   ## number of scenarios\nnv = 2   ## recourse variables per scenario\nnd = 1   ## design variables\nweight = 1.0 / ns\n\n0.3333333333333333\n\nTwo annotate the scenario for each variable and constraint, we can use the scenario we need to start with a special ExaCore that supports such scenario annotations, which can be created by calling TwoStageExaCore(concrete = Val(true)).\n\ncore = TwoStageExaCore(concrete = Val(true))\n\nAn ExaCore\n\n  Float type: ...................... Float64\n  Array type: ...................... Vector{Float64}\n  Backend: ......................... Nothing\n\n  number of objective patterns: .... 0\n  number of constraint patterns: ... 0\n\n\nNow we can define the design variable and recourse variables. The scenario keyword argument allows us to specify which scenario(s) each variable belongs to. For the design variable d, we set scenario = 0 to indicate that it is shared across all scenarios.\n\n@add_var(core, d; start = 1.0, lvar = 0.0, uvar = Inf, scenario = 0)  ## design variable d\n\nExaModels.Var{Int64}(1)\n\nFor the recourse variables v, we specify scenario = [i for i=1:ns, j=1:nv] to indicate that each variable v[s,i] belongs to scenario s. This allows us to define scenario-specific constraints and objectives that involve these recourse variables.\n\n@add_var(core, v, ns, nv; start = 1.0, lvar = 0.0, uvar = Inf, scenario = [i for i=1:ns, j=1:nv])  ## recourse variables v\n\nVariable\n\n  x ∈ R^{3 × 2}\n\n\nNow we can define the constraints and objective function. The scenario keyword argument in the constraint and objective functions allows us to specify which scenario(s) each constraint or objective term belongs to.\n\n@add_con(core, v[s,1] - v[s,2]^2 for s in 1:ns; lcon = 0.0, scenario = 1:ns)\n\n@add_obj(core, d^2)\n@add_obj(core, weight * (v[s,i] - d)^2 for s in 1:ns, i in 1:nv)\n\nm = ExaModel(core)\n\nAn ExaModel{Float64, Vector{Float64}, ...}\n\n  Problem name: Generic\n   All variables: ████████████████████ 7      All constraints: ████████████████████ 3     \n            free: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                 free: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n           lower: ████████████████████ 7                lower: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n           upper: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                upper: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n         low/upp: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0              low/upp: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n           fixed: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                fixed: ████████████████████ 3     \n          infeas: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0               infeas: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n            nnzh: ( 21.43% sparsity)   22              linear: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n                                                    nonlinear: ████████████████████ 3     \n                                                         nnzj: ( 71.43% sparsity)   6     \n                                                     lin_nnzj: (------% sparsity)         \n                                                     nln_nnzj: ( 71.43% sparsity)   6     \n\n\n\nNow we can solve the model as usual.\n\nipopt(m)\n\n\"Execution stats: first-order stationary\"\n\nIf the solver knows how to exploit the scenario structure, the structure-exploiting method can be used.\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"guide/#guide","page":"Getting Started","title":"Getting Started","text":"ExaModels can create nonlinear programming models and allows solving the created models using NLP solvers (in particular, those that are interfaced with NLPModels, such as NLPModelsIpopt and MadNLP. This documentation page will describe how to use ExaModels to model and solve nonlinear optimization problems.\n\nWe will first consider the following simple nonlinear program [3]:\n\nbeginaligned\nmin_x_i_i=0^N sum_i=2^N  100(x_i-1^2-x_i)^2+(x_i-1-1)^2\ntextst   3x_i+1^3+2x_i+2-5+sin(x_i+1-x_i+2)sin(x_i+1+x_i+2)+4x_i+1-x_i e^x_i-x_i+1-3 = 0\nendaligned\n\nWe will follow the following Steps to create the model/solve this optimization problem.\n\nStep 0: import ExaModels.jl\nStep 1: create a ExaCore object, wherein we can progressively build an optimization model.\nStep 2: create optimization variables with @add_var (or add_var), while attaching it to previously created ExaCore.\nStep 3 (interchangable with Step 3): create objective function with @add_obj (or add_obj), while attaching it to previously created ExaCore.\nStep 4 (interchangable with Step 2): create constraints with @add_con (or add_con), while attaching it to previously created ExaCore.\nStep 5: create an ExaModel based on the ExaCore.\n\nNow, let's jump right in. We import ExaModels via (Step 0):\n\nusing ExaModels\n\nNow, all the functions that are necessary for creating model are imported to into Main.","category":"section"},{"location":"guide/#ExaCore","page":"Getting Started","title":"ExaCore","text":"An ExaCore object can be created simply by (Step 1):\n\nc = ExaCore(concrete = Val(true))\n\nAn ExaCore\n\n  Float type: ...................... Float64\n  Array type: ...................... Vector{Float64}\n  Backend: ......................... Nothing\n\n  number of objective patterns: .... 0\n  number of constraint patterns: ... 0\n\n\nThis is where our optimization model information will be progressively stored. This object is not yet an NLPModel, but it will essentially store all the necessary information.","category":"section"},{"location":"guide/#Variables","page":"Getting Started","title":"Variables","text":"Now, let's create the optimization variables. From the problem definition, we can see that we will need N scalar variables. We will choose N=10, and create the variable xinmathbbR^N with the following command:\n\nN = 10\n@add_var(c, x, N; start = (mod(i, 2) == 1 ? -1.2 : 1.0 for i = 1:N))\n\nVariable\n\n  x ∈ R^{10}\n\n\nThis creates the variable x, which we will be able to refer to when we create constraints/objective constraints. Also, this modifies the information in the ExaCore object properly so that later an optimization model can be properly created with the necessary information. Observe that we have used the keyword argument start to specify the initial guess for the solution. The variable upper and lower bounds can be specified in a similar manner. For example, if we wanted to set the lower bound of the variable x to 0.0 and the upper bound to 10.0, we could do it as follows:\n\n@add_var(c, x, N; start = (mod(i, 2) == 1 ? -1.2 : 1.0 for i = 1:N), lvar = 0.0, uvar = 10.0)","category":"section"},{"location":"guide/#Objective","page":"Getting Started","title":"Objective","text":"The objective can be set as follows:\n\n@add_obj(c, 100 * (x[i-1]^2 - x[i])^2 + (x[i-1] - 1)^2 for i = 2:N)\n\nObjective\n\n  min (...) + ∑_{p ∈ P} f(x,θ,p)\n\n  where |P| = 9\n\n\nnote: Note\nNote that the terms here are summed, without explicitly using sum( ... ) syntax.","category":"section"},{"location":"guide/#Constraints","page":"Getting Started","title":"Constraints","text":"The constraints can be set as follows:\n\n@add_con(\n    c,\n    3x[i+1]^3 + 2 * x[i+2] - 5 + sin(x[i+1] - x[i+2])sin(x[i+1] + x[i+2]) + 4x[i+1] -\n    x[i]exp(x[i] - x[i+1]) - 3 for i = 1:(N-2)\n)\n\nConstraint\n\n  s.t. (...)\n       g♭ ≤ [g(x,θ,p)]_{p ∈ P} ≤ g♯\n\n  where |P| = 8\n\n\nNote that ExaModels always assume that the constraints are doubly-bounded inequalities. That is, the constraint above is treated as\n\n g^flat leq leftg^(m)(x q_j)right_jin J_m +sum_nin N_msum_kin K_nh^(n)(x s^(n)_k) leq g^sharp\n\nwhere g^\\flat and g^\\sharp are the lower and upper bounds of the constraint, respectively. In this case, both bounds are zero, i.e., g^\\flat = g^\\sharp = 0.\n\nYou can use the keyword arguments lcon and ucon to specify the lower and upper bounds of the constraints, respectively. For example, if we wanted to set the lower bound of the constraint to -1 and the upper bound to 1, we could do it as follows:\n\n@add_con(\n    c,\n    3x[i+1]^3 + 2 * x[i+2] - 5 + sin(x[i+1] - x[i+2])sin(x[i+1] + x[i+2]) + 4x[i+1] -\n    x[i]exp(x[i] - x[i+1]) - 3 for i = 1:(N-2);\n    lcon = -1.0, ucon = 1.0\n)\n\nConstraint\n\n  s.t. (...)\n       g♭ ≤ [g(x,θ,p)]_{p ∈ P} ≤ g♯\n\n  where |P| = 8\n\n\nIf you want to create a single-bounded constraint, you can set lcon to -Inf or ucon to Inf. For example, if we wanted to set the lower bound of the constraint to -1 and the upper bound to infinity, we could do it as follows:\n\n@add_con(\n    c,\n    3x[i+1]^3 + 2 * x[i+2] - 5 + sin(x[i+1] - x[i+2])sin(x[i+1] + x[i+2]) + 4x[i+1] -\n    x[i]exp(x[i] - x[i+1]) - 3 for i = 1:(N-2);\n    lcon = -1.0, ucon = Inf\n)\n\nConstraint\n\n  s.t. (...)\n       g♭ ≤ [g(x,θ,p)]_{p ∈ P} ≤ g♯\n\n  where |P| = 8\n","category":"section"},{"location":"guide/#Subexpressions","page":"Getting Started","title":"Subexpressions","text":"When complex expressions are reused across multiple objectives or constraints, you can define them as subexpressions using @add_expr (or add_expr). This improves code readability and avoids duplicating the expression tree.\n\nSubexpressions are inlined: when you index s[i], the original expression is substituted directly — no auxiliary variables or equality constraints are created. Derivative code is shared across all uses of the same subexpression pattern.\n\nHere's a simple example:\n\nc2 = ExaCore(concrete = Val(true))\n@add_var(c2, y, N; start = 1.0)\n\nVariable\n\n  x ∈ R^{10}\n\n\nDefine a subexpression for y[i]^2\n\n@add_expr(c2, s, y[i]^2 for i in 1:N)\n\nSubexpression (reduced)\n\n  s ∈ R^{10}\n\n\nNow s[i] can be used in objectives and constraints\n\n@add_obj(c2, (s[i] - 1)^2 for i in 1:N)\n@add_con(c2, s[i] + s[i + 1] for i in 1:(N - 1); lcon = 0.0)\n\nConstraint\n\n  s.t. (...)\n       g♭ ≤ [g(x,θ,p)]_{p ∈ P} ≤ g♯\n\n  where |P| = 9\n\n\nMulti-dimensional subexpressions are also supported with automatic dimension inference:\n\n@add_expr(c, dx, x[t, i] - x[t-1, i] for t in 1:T, i in 1:N)\n# dx[t, i] can now be used in constraints\n@add_con(c, dx[t, i] - something for t in 1:T, i in 1:N)\n\nFor a comprehensive example using subexpressions, see the Distillation Column example.","category":"section"},{"location":"guide/#ExaModel","page":"Getting Started","title":"ExaModel","text":"Finally, we are ready to create an ExaModel from the data we have collected in ExaCore. Since ExaCore includes all the necessary information, we can do this simply by:\n\nm = ExaModel(c)\n\nAn ExaModel{Float64, Vector{Float64}, ...}\n\n  Problem name: Generic\n   All variables: ████████████████████ 10     All constraints: ████████████████████ 24    \n            free: ████████████████████ 10                free: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n           lower: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                lower: ███████⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 8     \n           upper: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                upper: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n         low/upp: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0              low/upp: ███████⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 8     \n           fixed: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                fixed: ███████⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 8     \n          infeas: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0               infeas: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n            nnzh: (-210.91% sparsity)   171             linear: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n                                                    nonlinear: ████████████████████ 24    \n                                                         nnzj: ( 70.00% sparsity)   72    \n                                                     lin_nnzj: (------% sparsity)         \n                                                     nln_nnzj: ( 70.00% sparsity)   72    \n\n\n\nNow, we got an optimization model ready to be solved. This problem can be solved with for example, with the Ipopt solver, as follows.\n\nusing NLPModelsIpopt\nresult = ipopt(m)\n\n\"Execution stats: first-order stationary\"\n\nHere, result is an AbstractExecutionStats, which typically contains the solution information. We can check several information as follows.\n\nprintln(\"Status: $(result.status)\")\nprintln(\"Number of iterations: $(result.iter)\")\n\nStatus: first_order\nNumber of iterations: 8\n","category":"section"},{"location":"guide/#Solutions","page":"Getting Started","title":"Solutions","text":"The solution values for variable x can be inquired by:\n\nsol = solution(result, x)\n\n10-element view(::Vector{Float64}, 1:10) with eltype Float64:\n -0.9505563573613093\n  0.9139008176388945\n  0.9890905176644905\n  0.9985592422681151\n  0.9998087408802769\n  0.9999745932450962\n  0.9999966246997652\n  0.999999551252415\n  0.9999999449191489\n  0.9999999300651202\n\nThis will return the primal solution of the variable x as a vector. Dual solutions can be inquired similarly, by using the multipliers function.\n\nExaModels provide several APIs similar to this:\n\nsolution inquires the primal solution.\nmultipliers inquires the dual solution.\nmultipliers_L inquires the lower bound dual solution.\nmultipliers_U inquires the upper bound dual solution.\n\nThis concludes a short tutorial on how to use ExaModels to model and solve optimization problems. Want to learn more? Take a look at the following examples, which provide further tutorial on how to use ExaModels.jl. Each of the examples are designed to instruct a few additional techniques.\n\nExample: Quadrotor: modeling multiple types of objective values and constraints.\nExample: Distillation Column: using subexpressions and two-dimensional index sets.\nExample: Optimal Power Flow: handling complex data and using constraint augmentation.\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"core/#ExaModels","page":"API Manual","title":"ExaModels","text":"","category":"section"},{"location":"core/#ExaModels.ExaModels","page":"API Manual","title":"ExaModels.ExaModels","text":"ExaModels\n\nAn algebraic modeling and automatic differentiation tool in Julia, specialized for SIMD-parallel evaluation of nonlinear programs on CPUs and GPUs.\n\nComputation graph\n\nExpressions are represented as trees of AbstractNode subtypes:\n\nVar / ParIndexed — decision variables and data fields\nNode1 / Node2 — unary / binary operations\nConstant{T} — compile-time scalar constant; the value T is stored as a type parameter so it is visible to the compiler and to juliac --trim=safe without any runtime storage.\nSumNode / ProdNode — reduction over a tuple of nodes\n\nAlgebraic simplification\n\nOperations involving Constant{T} are simplified at model-construction time: x * Constant(1) → x, x ^ Constant(2) → abs2(x), etc. (see specialization.jl).  Combined Constant OP Constant expressions are folded to a new Constant via the rules in register.jl.\n\nFor more information, please visit https://github.com/exanauts/ExaModels.jl\n\n\n\n\n\n","category":"module"},{"location":"core/#ExaModels.AbstractAdjointNode","page":"API Manual","title":"ExaModels.AbstractAdjointNode","text":"AbstractAdjointNode\n\nAbstract type for nodes in the first-order (gradient) forward-pass tree.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.AbstractExaModel","page":"API Manual","title":"ExaModels.AbstractExaModel","text":"AbstractExaModel\n\nAn abstract type for ExaModel, which is a subtype of NLPModels.AbstractNLPModel.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.AbstractNode","page":"API Manual","title":"ExaModels.AbstractNode","text":"AbstractNode\n\nRoot abstract type for all nodes in the ExaModels symbolic computation graph. Every node is callable as node(i, x, θ) and returns the scalar value of the expression at the current evaluation point, where i is the iteration index, x the primal variable vector, and θ the parameter vector.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.AbstractSecondAdjointNode","page":"API Manual","title":"ExaModels.AbstractSecondAdjointNode","text":"AbstractSecondAdjointNode\n\nAbstract type for nodes in the second-order (Hessian) reverse-pass tree.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.AdjointNode1","page":"API Manual","title":"ExaModels.AdjointNode1","text":"AdjointNode1{F, T, I} <: AbstractAdjointNode\n\nGradient-pass node for a unary operation F.  Stores the primal value and the partial derivative alongside the child so a single forward sweep simultaneously computes both.\n\nFields\n\nx::T: primal value F(inner.x)\ny::T: derivative F'(inner.x)\ninner::I: child node\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.AdjointNode2","page":"API Manual","title":"ExaModels.AdjointNode2","text":"AdjointNode2{F, T, I1, I2} <: AbstractAdjointNode\n\nGradient-pass node for a binary operation F.  Stores the primal value and both partial derivatives.\n\nFields\n\nx::T: primal value F(inner1.x, inner2.x)\ny1::T: partial derivative w.r.t. first argument\ny2::T: partial derivative w.r.t. second argument\ninner1::I1: left child\ninner2::I2: right child\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.AdjointNodeSource","page":"API Manual","title":"ExaModels.AdjointNodeSource","text":"AdjointNodeSource{VT}\n\nFactory for AdjointNodeVar leaves.  Indexing with i returns AdjointNodeVar(i, inner[i]), seeding the gradient-pass tree with the current primal value.\n\nFields\n\ninner::VT: primal variable vector (or nothing for a zero-valued seed)\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.AdjointNodeVar","page":"API Manual","title":"ExaModels.AdjointNodeVar","text":"AdjointNodeVar{I, T} <: AbstractAdjointNode\n\nLeaf node in the gradient-pass tree corresponding to a decision variable.\n\nFields\n\ni::I: variable index\nx::T: primal value x[i] at the current evaluation point\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.AdjointNull","page":"API Manual","title":"ExaModels.AdjointNull","text":"AdjointNull{V} <: AbstractAdjointNode\n\nLeaf node in the first-order adjoint tree representing a constant (zero contribution to the gradient).  Carries the primal value x so that upstream nodes can read it without recomputation.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.CompressedNLPModel","page":"API Manual","title":"ExaModels.CompressedNLPModel","text":"CompressedNLPModel\n\nA wrapper around an AbstractNLPModel that sums duplicate (row, col) entries in the sparse Jacobian and Hessian.\n\nDuplicates arise when multiple constraint or objective patterns contribute to the same matrix position (e.g. after augmentation via add_con!). CompressedNLPModel detects them once at construction and accumulates them on every subsequent jac_coord! / hess_coord! call, so callers receive a matrix with no repeated coordinates.\n\nConstruct via CompressedNLPModel(m).\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.CompressedNLPModel-Tuple{Any}","page":"API Manual","title":"ExaModels.CompressedNLPModel","text":"CompressedNLPModel(m)\n\nWraps m in a CompressedNLPModel.\n\nQueries the full Jacobian and Hessian sparsity patterns from m, identifies duplicate (row, col) pairs, builds pointer arrays for O(nnz) accumulation on subsequent jac_coord! / hess_coord! calls.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.Compressor","page":"API Manual","title":"ExaModels.Compressor","text":"Compressor{I}\n\nData structure for the sparse index\n\nFields:\n\ninner::I: stores the sparse index as a tuple form\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.Constant","page":"API Manual","title":"ExaModels.Constant","text":"Constant{T} <: AbstractNode\n\nA compile-time constant node whose value T is embedded as a type parameter.\n\nDesign rationale\n\nBecause T is a type parameter rather than a struct field, the Julia compiler (and juliac --trim=safe) can propagate T concretely through every downstream Node1 / Node2 type, making the entire computation graph type-stable with no runtime storage for the constant.\n\nConstruction\n\nConstant(2)      # → Constant{2}()\nConstant(3.14)   # → Constant{3.14}()\n\nEvaluation\n\nc = Constant(42)\nc(i, x, θ)  # → 42\n\nAlgebraic simplification\n\nspecialization.jl registers identities for Constant combined with AbstractNode operands:\n\nexpression simplification\nx + Constant(0) x\nx * Constant(1) x\nx / Constant(1) x\nx ^ Constant(0) Constant(1)\nx ^ Constant(1) x\nx ^ Constant(2) Node1(abs2, x)\nx ^ Constant(-1) inv(x)\nConstant(0) * x Constant(0)\nConstant(0) / x Constant(0)\n\nThese rules fire at model-construction time (when the ExaCore is being built), collapsing trivial branches before the graph is finalized.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.Constraint","page":"API Manual","title":"ExaModels.Constraint","text":"Constraint\n\nA block of constraints added to an ExaCore via add_con / @add_con. Each element of the iterator corresponds to one constraint row. Row k of this block maps to global constraint index offset + k. Dual solution values can be retrieved with multipliers.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.ConstraintAugmentation","page":"API Manual","title":"ExaModels.ConstraintAugmentation","text":"ConstraintAugmentation\n\nAn augmentation layer added to an existing Constraint via add_con! / @add_con!. Each element of the iterator yields an idx => expr pair: expr is accumulated into the constraint row identified by idx at evaluation time. Multiple ConstraintAugmentation objects can be stacked on the same base constraint to aggregate contributions from several data sources (e.g. summing arc flows into nodal balance constraints).\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.ExaCore","page":"API Manual","title":"ExaModels.ExaCore","text":"ExaCore([array_eltype::Type; backend = nothing, minimize = true, name = :Generic])\n\nCreates an intermediate data object ExaCore, which later can be used for creating an ExaModel\n\nExample\n\njulia> using ExaModels\n\njulia> c = ExaCore(concrete = Val(true))\nAn ExaCore\n\n  Float type: ...................... Float64\n  Array type: ...................... Vector{Float64}\n  Backend: ......................... Nothing\n\n  number of objective patterns: .... 0\n  number of constraint patterns: ... 0\n\njulia> c = ExaCore(Float32; concrete = Val(true))\nAn ExaCore\n\n  Float type: ...................... Float32\n  Array type: ...................... Vector{Float32}\n  Backend: ......................... Nothing\n\n  number of objective patterns: .... 0\n  number of constraint patterns: ... 0\n\njulia> using CUDA\n\njulia> c = ExaCore(Float32; backend = CUDABackend(), concrete = Val(true))\nAn ExaCore\n\n  Float type: ...................... Float32\n  Array type: ...................... CUDA.CuArray{Float32, 1, CUDA.DeviceMemory}\n  Backend: ......................... CUDA.CUDAKernels.CUDABackend\n\n  number of objective patterns: .... 0\n  number of constraint patterns: ... 0\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.ExaModel-Tuple{C} where C<:ExaCore","page":"API Manual","title":"ExaModels.ExaModel","text":"ExaModel(core)\n\nReturns an ExaModel object, which can be solved by nonlinear optimization solvers within JuliaSmoothOptimizer ecosystem, such as NLPModelsIpopt or MadNLP.\n\nExample\n\njulia> using ExaModels\n\njulia> c = ExaCore(concrete = Val(true));                           # create an ExaCore object\n\njulia> c, x = add_var(c, 1:10);               # create variables\n\njulia> c, _ = add_obj(c, x[i]^2 for i in 1:10); # set objective function\n\njulia> m = ExaModel(c)                          # create an ExaModel object\nAn ExaModel{Float64, Vector{Float64}, ...}\n\n  Problem name: Generic\n   All variables: ████████████████████ 10     All constraints: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0\n            free: ████████████████████ 10                free: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0\n           lower: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                lower: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0\n           upper: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                upper: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0\n         low/upp: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0              low/upp: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0\n           fixed: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                fixed: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0\n          infeas: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0               infeas: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0\n            nnzh: ( 81.82% sparsity)   10              linear: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0\n                                                    nonlinear: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0\n                                                         nnzj: (------% sparsity)\n                                                     lin_nnzj: (------% sparsity)\n                                                     nln_nnzj: (------% sparsity)\n\njulia> using NLPModelsIpopt\n\njulia> result = ipopt(m; print_level=0)    # solve the problem\n\"Execution stats: first-order stationary\"\n\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.Expression","page":"API Manual","title":"ExaModels.Expression","text":"Expression\n\nA subexpression created by add_expr / @add_expr. When indexed (e.g. s[i]), the expression is substituted directly into the enclosing objective or constraint — no auxiliary variables or equality constraints are introduced.  Use Expression to share common sub-expressions across multiple objectives or constraints without duplicating the expression tree.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.LegacyExaCore","page":"API Manual","title":"ExaModels.LegacyExaCore","text":"LegacyExaCore{T,VT,B,S}\n\nA mutable wrapper around an immutable ExaCore that provides the legacy mutating API (variable, constraint, etc.).\n\nExaCore() returns a LegacyExaCore by default. Use ExaCore(concrete = Val(true)) to obtain the bare immutable ExaCore required for AOT compilation.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.Node1","page":"API Manual","title":"ExaModels.Node1","text":"Node1{F, I} <: AbstractNode\n\nAn interior node representing a unary operation F applied to one child node.\n\nEvaluated as F(inner(i, x, θ)).\n\nFields\n\ninner::I: child node\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.Node2","page":"API Manual","title":"ExaModels.Node2","text":"Node2{F, I1, I2} <: AbstractNode\n\nAn interior node representing a binary operation F applied to two children. Either child can be a node or a plain scalar (e.g. Real), allowing numeric coefficients to be stored directly without wrapping in Constant.\n\nEvaluated as F(inner1(i, x, θ), inner2(i, x, θ)).\n\nFields\n\ninner1::I1: left child\ninner2::I2: right child\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.Null","page":"API Manual","title":"ExaModels.Null","text":"Null{T} <: AbstractNode\n\nA leaf node that always evaluates to a fixed scalar.  The value is stored in a field (as opposed to Constant, which encodes the value as a type parameter).  Used when the constant is not known at compile time.\n\nNull() creates a zero-valued node; Null(v) creates a node that returns T(v) where T is the element type of the primal vector.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.Objective","page":"API Manual","title":"ExaModels.Objective","text":"Objective\n\nAn objective term group added to an ExaCore via add_obj / @add_obj. All Objective objects in a core are summed at evaluation time to form the total objective value.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.ParIndexed","page":"API Manual","title":"ExaModels.ParIndexed","text":"ParIndexed{I, J} <: AbstractNode\n\nA node representing the lookup inner.J (or inner[J]) where inner is a ParSource or another ParIndexed.  The field/index J is encoded as a type parameter so that getfield / getindex can be resolved at compile time.\n\nConstructed implicitly via getproperty / getindex on a ParSource.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.ParSource","page":"API Manual","title":"ExaModels.ParSource","text":"ParSource <: AbstractNode\n\nSentinel node used as the root of a parameter (data) array.  Indexing or accessing fields on a ParSource returns a ParIndexed node that encodes the access path as nested type parameters for zero-overhead data lookup.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.Parameter","page":"API Manual","title":"ExaModels.Parameter","text":"Parameter\n\nA handle to a block of model parameters added to an ExaCore via add_par / @add_par. Parameter values can be updated at any time with set_parameter! without rebuilding the model. Use indexing (e.g. θ[i]) to embed parameter values in expressions.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.ProdNode","page":"API Manual","title":"ExaModels.ProdNode","text":"ProdNode{I} <: AbstractNode\n\nA node representing the product of a tuple of child nodes.\n\nConstructed by exa_prod.  See SumNode for design notes.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.SIMDFunction","page":"API Manual","title":"ExaModels.SIMDFunction","text":"SIMDFunction(gen::Base.Generator, o0 = 0, o1 = 0, o2 = 0)\n\nReturns a SIMDFunction using the gen.\n\nArguments:\n\ngen: an iterable function specified in Base.Generator format\no0: offset for the function evaluation\no1: offset for the derivative evalution\no2: offset for the second-order derivative evalution\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.SecondAdjointNode1","page":"API Manual","title":"ExaModels.SecondAdjointNode1","text":"SecondAdjointNode1{F, T, I} <: AbstractSecondAdjointNode\n\nHessian-pass node for a unary operation F.  A single forward sweep stores the primal value, first derivative, and second derivative needed for the reverse Hessian accumulation.\n\nFields\n\nx::T: primal value F(inner.x)\ny::T: first derivative F'(inner.x)\nh::T: second derivative F''(inner.x)\ninner::I: child node\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.SecondAdjointNode2","page":"API Manual","title":"ExaModels.SecondAdjointNode2","text":"SecondAdjointNode2{F, T, I1, I2} <: AbstractSecondAdjointNode\n\nHessian-pass node for a binary operation F.\n\nFields\n\nx::T: primal value F(inner1.x, inner2.x)\ny1::T: partial derivative w.r.t. first argument\ny2::T: partial derivative w.r.t. second argument\nh11::T: second partial w.r.t. first argument\nh12::T: mixed second partial\nh22::T: second partial w.r.t. second argument\ninner1::I1: left child\ninner2::I2: right child\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.SecondAdjointNodeSource","page":"API Manual","title":"ExaModels.SecondAdjointNodeSource","text":"SecondAdjointNodeSource{VT}\n\nFactory for SecondAdjointNodeVar leaves.  Indexing with i returns SecondAdjointNodeVar(i, inner[i]), seeding the Hessian-pass tree.\n\nFields\n\ninner::VT: primal variable vector (or nothing for a zero-valued seed)\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.SecondAdjointNodeVar","page":"API Manual","title":"ExaModels.SecondAdjointNodeVar","text":"SecondAdjointNodeVar{I, T} <: AbstractSecondAdjointNode\n\nLeaf node in the Hessian-pass tree corresponding to a decision variable.\n\nFields\n\ni::I: variable index\nx::T: primal value x[i] at the current evaluation point\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.SecondAdjointNull","page":"API Manual","title":"ExaModels.SecondAdjointNull","text":"SecondAdjointNull{V} <: AbstractSecondAdjointNode\n\nLeaf node in the second-order adjoint tree representing a constant (zero contribution to both the gradient and the Hessian).  Carries the primal value x for upstream consumption.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.SumNode","page":"API Manual","title":"ExaModels.SumNode","text":"SumNode{I} <: AbstractNode\n\nA node representing the sum of a tuple of child nodes.\n\nConstructed by exa_sum.  Within @add_obj, @add_con, and @add_expr macros, sum(body for k in range) is automatically rewritten to exa_sum(k -> body, Val(range)) with the Val hoisted outside the generator closure for type stability under juliac --trim=safe.\n\nIn adjoint / second-adjoint mode the children are evaluated and folded via reduce(+, …) (or reduce(*, …) for ProdNode), reusing the existing registered + / * dispatch.  No dedicated adjoint node types are needed.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.TimedNLPModel","page":"API Manual","title":"ExaModels.TimedNLPModel","text":"TimedNLPModel\n\nA transparent wrapper around any AbstractNLPModel that records wall-clock timings and call counts for each NLP callback (obj, cons!, grad!, jac_coord!, hess_coord!, jac_structure!, hess_structure!).\n\nStatistics accumulate in the stats field and can be printed with print(m). Construct via TimedNLPModel(m).\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.TimedNLPModel-Tuple{Any}","page":"API Manual","title":"ExaModels.TimedNLPModel","text":"TimedNLPModel(m)\n\nWraps m in a TimedNLPModel with all counters and timers reset to zero.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.TimedNLPModel-Tuple{ExaCore}","page":"API Manual","title":"ExaModels.TimedNLPModel","text":"TimedNLPModel(core::ExaCore; kwargs...)\n\nBuilds an ExaModel from core (forwarding kwargs...) and wraps it in a TimedNLPModel.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.Var","page":"API Manual","title":"ExaModels.Var","text":"Var{I} <: AbstractNode\n\nA leaf node representing the i-th decision variable.\n\nWhen evaluated as v(i, x, θ), returns x[v.i] (or x[v.i(i,x,θ)] when the index is itself a node).\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.VarSource","page":"API Manual","title":"ExaModels.VarSource","text":"VarSource <: AbstractNode\n\nSentinel node used as the root of a variable array.  Indexing a VarSource with an integer i returns Var(i), building the leaf node that refers to the i-th decision variable.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.Variable","page":"API Manual","title":"ExaModels.Variable","text":"Variable\n\nA handle to a block of optimization variables added to an ExaCore via add_var / @add_var. Use indexing (e.g. x[i]) to reference individual entries in objective and constraint expressions. Retrieve solution values with solution.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.WrapperNLPModel","page":"API Manual","title":"ExaModels.WrapperNLPModel","text":"WrapperNLPModel\n\nAn NLPModels.AbstractNLPModel wrapper that bridges a model whose internal array type differs from the host array type (e.g. a GPU-backed ExaModel wrapped for a CPU-only solver).  All NLP callbacks are forwarded to the inner model through intermediate copy buffers.\n\nUse WrapperNLPModel(m) or WrapperNLPModel(VT, m) rather than constructing this struct directly.\n\n\n\n\n\n","category":"type"},{"location":"core/#ExaModels.WrapperNLPModel-Tuple{Any, Any}","page":"API Manual","title":"ExaModels.WrapperNLPModel","text":"WrapperNLPModel(VT, m)\n\nReturns a WrapperModel{T,VT} wrapping m <: AbstractNLPModel{T}\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.WrapperNLPModel-Tuple{Any}","page":"API Manual","title":"ExaModels.WrapperNLPModel","text":"WrapperNLPModel(m)\n\nReturns a WrapperNLPModel{Float64,Vector{Float64}} wrapping m, forwarding all NLP callbacks through Float64 CPU copy buffers.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels._needs_overload-Tuple{Any, Any}","page":"API Manual","title":"ExaModels._needs_overload","text":"_needs_overload(f, types)\n\nReturn true when ExaModels should add a method for f with the given argument types.\n\nPlain hasmethod is too conservative for Base generics such as max(x,y) = ifelse(isless(x,y),y,x): those definitions match any AbstractNode argument, so hasmethod returns true and would prevent the ExaModels-specific overload from being added.  We instead check the owner module of the matching method and only skip when ExaModels already owns it.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.add_con!-Union{Tuple{C}, Tuple{T}, Tuple{C, Any, Base.Generator}} where {T, C<:(ExaCore{T, VT} where VT<:AbstractVector{T})}","page":"API Manual","title":"ExaModels.add_con!","text":"add_con!(core, c1, generator)\n\nAugments the existing constraint c1 by adding extra expression terms to a subset of its rows, and returns (core, ConstraintAugmentation).\n\nThis is the primary mechanism for building constraints that aggregate contributions from multiple data sources — for example, nodal power-balance constraints that sum flows over all arcs incident to each bus.  Each call to add_con! appends one new \"augmentation layer\"; multiple layers for the same base constraint are summed at evaluation time.\n\nThe bounds (lcon/ucon) remain those set on the original c1 and cannot be changed via add_con!.\n\nArguments\n\ncore: The ExaCore to modify.\nc1: The base Constraint (or a previous ConstraintAugmentation) whose rows are being augmented.\ngenerator: A Base.Generator yielding idx => expr pairs, where\nidx is an index (or tuple of indices) into c1 identifying which constraint row receives the term, and\nexpr is the scalar expression to add to that row.\n\nNotes\n\nThe index idx must be a valid index of c1's iterator (e.g. an integer for a 1-D constraint, or a tuple (i, j) for a multi-dimensional one).\nOne generator element maps to one non-zero Jacobian row; elements with the same idx are accumulated.\nThe iterator of the generator becomes the SIMD work set, so performance is best when it is a contiguous collection (array, range, or product iterator).\n\nExample\n\nSingle-index augmentation — add sin(x[i+1]) to constraint rows 4, 5, 6:\n\njulia> using ExaModels\n\njulia> c = ExaCore(concrete = Val(true));\n\njulia> c, x = add_var(c, 10);\n\njulia> c, c1 = add_con(c, x[i] + x[i+1] for i=1:9; lcon = -1, ucon = (1+i for i=1:9));\n\njulia> c, c2 = add_con!(c, c1, i => sin(x[i+1]) for i=4:6);\n\njulia> c2\nConstraint Augmentation\n\n  s.t. (...)\n       g♭ ≤ (...) + ∑_{p ∈ P} h(x,θ,p) ≤ g♯\n\n  where |P| = 3\n\nMulti-source augmentation (typical power-flow use case) — accumulate arc flows into bus balance constraints:\n\nc, bus = add_con(c, pd[b.i] + gs[b.i]*vm[b.i]^2 for b in data.bus)   # one row per bus\nadd_con!(c, bus, arc.bus => p[arc.i] for arc in data.arc)              # add arc flows\nadd_con!(c, bus, gen.bus => -pg[gen.i] for gen in data.gen)            # subtract generation\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.add_con-Union{Tuple{C}, Tuple{T}, Tuple{C, Any}} where {T, C<:(ExaCore{T, VT} where VT<:AbstractVector{T})}","page":"API Manual","title":"ExaModels.add_con","text":"add_con(core, n; start = 0, lcon = 0, ucon = 0, name = nothing)\n\nAdds n empty constraints to core and returns (core, Constraint). No expression is attached initially — use add_con! / @add_con! to accumulate terms into the rows afterwards.\n\nWhen name is given as Val(:name), the constraint is also accessible as core.name or model.name.\n\nExample\n\njulia> using ExaModels\n\njulia> c = ExaCore(concrete = Val(true));\n\njulia> c, x = add_var(c, 10);\n\njulia> c, g = add_con(c, 9; lcon = -1.0, ucon = 1.0);\n\njulia> c, _ = add_con!(c, g, i => x[i] + x[i+1] for i = 1:9);\n\njulia> g\nConstraint\n\n  s.t. (...)\n       g♭ ≤ [g(x,θ,p)]_{p ∈ P} ≤ g♯\n\n  where |P| = 9\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.add_con-Union{Tuple{C}, Tuple{T}, Tuple{C, Base.Generator, Vararg{Base.Generator}}} where {T, C<:(ExaCore{T, VT} where VT<:AbstractVector{T})}","page":"API Manual","title":"ExaModels.add_con","text":"add_con(core, gen, gens...; kwargs...)\n\nCreate a constraint from the first generator, then augment it with each subsequent generator via add_con!. Returns (core, Constraint).\n\nKeyword Arguments\n\nstart: Initial guess for the dual solution. Can be a Number, AbstractArray, or Generator.\nlcon : Constraint lower bound. Can be a Number, AbstractArray, or Generator.\nucon : Constraint upper bound. Can be a Number, AbstractArray, or Generator.\nname : When given as Val(:name), registers the constraint for later retrieval as core.name or model.name.\nkwargs...: Additional keyword arguments forwarded to add_con (e.g. scenario tags).\n\nExample\n\nc, g = add_con(c,\n    (x[i] for i in 1:N),\n    (i => sin(x[i]) for i in 1:N);\n    lcon = 0.0, ucon = 0.0,\n)\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.add_con-Union{Tuple{C}, Tuple{T}, Tuple{C, Base.Generator}} where {T, C<:(ExaCore{T, VT} where VT<:AbstractVector{T})}","page":"API Manual","title":"ExaModels.add_con","text":"add_con(core, generator; start = 0, lcon = 0, ucon = 0, kwargs...)\n\nAdds constraints specified by a generator to core, and returns (core, Constraint).\n\nKeyword Arguments\n\nstart: The initial guess of the dual solution. Can either be Number, AbstractArray, or Generator.\nlcon : The constraint lower bound. Can either be Number, AbstractArray, or Generator.\nucon : The constraint upper bound. Can either be Number, AbstractArray, or Generator.\nname : When given as Val(:name), registers the constraint in core for later retrieval as core.name or model.name. See @add_con for the idiomatic named interface.\nkwargs...: Additional keyword arguments for constraint tags (e.g., scenario for two-stage models)\n\nExample\n\njulia> using ExaModels\n\njulia> c = ExaCore(concrete = Val(true));\n\njulia> c, x = add_var(c, 10);\n\njulia> c, con = add_con(c, x[i] + x[i+1] for i=1:9; lcon = -1, ucon = (1+i for i=1:9));\n\njulia> con\nConstraint\n\n  s.t. (...)\n       g♭ ≤ [g(x,θ,p)]_{p ∈ P} ≤ g♯\n\n  where |P| = 9\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.add_con-Union{Tuple{N}, Tuple{C}, Tuple{T}, Tuple{C, N}, Tuple{C, N, Any}} where {T, C<:(ExaCore{T, VT} where VT<:AbstractVector{T}), N<:ExaModels.AbstractNode}","page":"API Manual","title":"ExaModels.add_con","text":"add_con(core, expr [, pars]; start = 0, lcon = 0, ucon = 0, name = nothing)\n\nLow-level form of add_con that accepts a pre-built AbstractNode expression expr evaluated over pars, and returns (core, Constraint).\n\nWhen name is given as Val(:name), the constraint is also accessible as core.name or model.name.\n\nPrefer the generator form (add_con(core, gen)) for typical use; this form is intended for code that builds expression trees programmatically.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.add_expr-Union{Tuple{C}, Tuple{T}, Tuple{C, Base.Generator}} where {T, C<:(ExaCore{T, VT} where VT<:AbstractVector{T})}","page":"API Manual","title":"ExaModels.add_expr","text":"add_expr(core, generator; name = nothing)\n\nCreates a subexpression from a generator and returns (core, Expression). The expression is stored for direct substitution (inlining) when indexed — no auxiliary variables or constraints are added to the problem.\n\nKeyword Arguments\n\nname: When given as Val(:name), registers the subexpression in core for later retrieval as core.name or model.name. See @add_expr for the idiomatic named interface.\n\nExample\n\njulia> using ExaModels\n\njulia> c = ExaCore(concrete = Val(true));\n\njulia> c, x = add_var(c, 10);\n\njulia> c, s = add_expr(c, x[i]^2 for i in 1:10);\n\njulia> s\nSubexpression (reduced)\n\n  s ∈ R^{10}\n\njulia> c, _ = add_obj(c, s[i] + s[i+1] for i in 1:9);\n\nMulti-dimensional example\n\nc = ExaCore(concrete = Val(true))\nc, x = add_var(c, 1:N, 1:K)\nitr = [(i, k) for i in 1:N, k in 1:K]\nc, s = add_expr(c, x[i, k]^2 for (i, k) in itr)\n# s[i, k] substitutes x[i,k]^2 directly\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.add_obj-Union{Tuple{C}, Tuple{T}, Tuple{C, Any}} where {T, C<:(ExaCore{T, VT} where VT<:AbstractVector{T})}","page":"API Manual","title":"ExaModels.add_obj","text":"add_obj(core::ExaCore, generator; name = nothing)\n\nAdds objective terms specified by a generator to core, and returns (core, Objective). The terms are summed.\n\nKeyword Arguments\n\nname: When given as Val(:name), registers the objective in core for later retrieval as core.name or model.name. See @add_obj for the idiomatic named interface.\n\nExample\n\njulia> using ExaModels\n\njulia> c = ExaCore(concrete = Val(true));\n\njulia> c, x = add_var(c, 10);\n\njulia> c, obj = add_obj(c, x[i]^2 for i=1:10);\n\njulia> obj\nObjective\n\n  min (...) + ∑_{p ∈ P} f(x,θ,p)\n\n  where |P| = 10\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.add_obj-Union{Tuple{N}, Tuple{C}, Tuple{T}, Tuple{C, N}, Tuple{C, N, Any}} where {T, C<:(ExaCore{T, VT} where VT<:AbstractVector{T}), N<:ExaModels.AbstractNode}","page":"API Manual","title":"ExaModels.add_obj","text":"add_obj(core::ExaCore, expr [, pars]; name = nothing)\n\nLow-level form of add_obj that accepts a pre-built AbstractNode expression expr evaluated over pars, and returns (core, Objective).\n\nWhen name is given as Val(:name), the objective is also accessible as core.name or model.name.\n\nPrefer the generator form (add_obj(core, gen)) for typical use; this form is intended for code that builds expression trees programmatically.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.add_par-Union{Tuple{C}, Tuple{T}, Tuple{C, AbstractArray}} where {T, C<:(ExaCore{T, VT} where VT<:AbstractVector{T})}","page":"API Manual","title":"ExaModels.add_par","text":"add_par(core, start::AbstractArray; name = nothing)\n\nAdds parameters with initial values specified by start, and returns (core, Parameter).\n\nKeyword Arguments\n\nname: When given as Val(:name), registers the parameter in core for later retrieval as core.name or model.name. See @add_par for the idiomatic named interface.\n\nExample\n\njulia> using ExaModels\n\njulia> c = ExaCore(concrete = Val(true));\n\njulia> c, θ = add_par(c, ones(10));\n\njulia> θ\nParameter\n\n  θ ∈ R^{10}\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.add_var-Union{Tuple{C}, Tuple{T}, Tuple{C, Base.Generator}} where {T, C<:(ExaCore{T, VT} where VT<:AbstractVector{T})}","page":"API Manual","title":"ExaModels.add_var","text":"add_var(core, gen::Base.Generator; kwargs...)\n\nCreate variables constrained to equal the expressions produced by gen. Equivalent to creating length(gen.iter) variables with equality constraints tying each to the corresponding generator expression. Returns (core, Variable).\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.add_var-Union{Tuple{C}, Tuple{T}, Tuple{C, Vararg{Any}}} where {T, C<:(ExaCore{T, VT} where VT<:AbstractVector{T})}","page":"API Manual","title":"ExaModels.add_var","text":"add_var(core, dims...; start = 0, lvar = -Inf, uvar = Inf, name = nothing, kwargs...)\n\nAdds variables with dimensions specified by dims to core. dims can be either Integer or UnitRange. Returns (core, Variable).\n\nKeyword Arguments\n\nstart: The initial guess of the solution. Can either be Number, AbstractArray, or Generator.\nlvar : The variable lower bound. Can either be Number, AbstractArray, or Generator.\nuvar : The variable upper bound. Can either be Number, AbstractArray, or Generator.\nname : When given as Val(:name), registers the variable in core for later retrieval as core.name or model.name. See @add_var for the idiomatic named interface.\nkwargs...: Additional keyword arguments for variable tags (e.g., scenario for two-stage models)\n\nExample\n\njulia> using ExaModels\n\njulia> c = ExaCore(concrete = Val(true));\n\njulia> c, x = add_var(c, 10; start = (sin(i) for i=1:10));\n\njulia> x\nVariable\n\n  x ∈ R^{10}\n\njulia> c, y = add_var(c, 2:10, 3:5; lvar = zeros(9,3), uvar = ones(9,3));\n\njulia> y\nVariable\n\n  x ∈ R^{9 × 3}\n\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.constraint!-Tuple{LegacyExaCore, Vararg{Any}}","page":"API Manual","title":"ExaModels.constraint!","text":"constraint!(core, c1, generator)\n\nDeprecated. Use add_con! instead.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.constraint-Tuple{LegacyExaCore, Vararg{Any}}","page":"API Manual","title":"ExaModels.constraint","text":"constraint(core, generator; start = 0, lcon = 0, ucon = 0, kwargs...)\n\nDeprecated. Use add_con instead.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.drpass-Union{Tuple{D}, Tuple{D, Any, Any}} where D<:Union{Real, ExaModels.AdjointNull}","page":"API Manual","title":"ExaModels.drpass","text":"drpass(d::D, y, adj)\n\nPerforms dense gradient evaluation via the reverse pass on the computation (sub)graph formed by forward pass\n\nArguments:\n\nd: first-order computation (sub)graph\ny: result vector\nadj: adjoint propagated up to the current node\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.exa_prod-Tuple{Any, Tuple{}}","page":"API Manual","title":"ExaModels.exa_prod","text":"exa_prod(f, itr)\nexa_prod(f, ::Val{range})\nexa_prod(gen::Base.Generator)\n\nBuild a ProdNode representing ∏ f(k) for k ∈ itr. Inside @add_obj, @add_con, and @add_expr macros, prod(body for k in range) is automatically rewritten to exa_prod(k -> body, Val(range)) with the Val hoisted outside the generator closure.\n\nSee exa_sum for supported iterators and juliac usage notes.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.exa_sum-Tuple{Any, Tuple{}}","page":"API Manual","title":"ExaModels.exa_sum","text":"exa_sum(f, itr)\nexa_sum(f, ::Val{range})\nexa_sum(gen::Base.Generator)\n\nBuild a SumNode representing ∑ f(k) for k ∈ itr. Inside @add_obj, @add_con, and @add_expr macros, sum(body for k in range) is automatically rewritten to exa_sum(k -> body, Val(range)) with the Val hoisted outside the generator closure.\n\nSupported iterators\n\nTuple: type-stable via tail recursion.\nUnitRange{Int}: type-stable when the length is a compile-time constant.\nVal{range} (preferred for juliac): exa_sum(f, Val(1:nc)) embeds the range in the type parameter, ensuring juliac --trim=safe can resolve Val{N}.\n\njuliac / AOT usage\n\nJulia's inference cannot propagate constants like nc = 3 through a generator closure boundary.  When calling add_con/add_obj programmatically (not via macro), hoist Val(range) outside the generator:\n\nv = Val(1:nc)                                          # outside generator\nc, con = add_con(c, (exa_sum(j -> x[j], v) for i in 1:nh))  # v captured\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.gradient!-NTuple{5, Any}","page":"API Manual","title":"ExaModels.gradient!","text":"gradient!(y, f, x, adj)\n\nPerforms dense gradient evalution\n\nArguments:\n\ny: result vector\nf: the function to be differentiated in SIMDFunction format\nx: variable vector\nadj: initial adjoint\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.grpass-Union{Tuple{D}, Tuple{D, Vararg{Any, 5}}} where D<:Union{Real, ExaModels.AdjointNull, ExaModels.ParIndexed}","page":"API Manual","title":"ExaModels.grpass","text":"grpass(d::D, comp, y, o1, cnt, adj)\n\nPerforms dsparse gradient evaluation via the reverse pass on the computation (sub)graph formed by forward pass\n\nArguments:\n\nd: first-order computation (sub)graph\ncomp: a Compressor, which helps map counter to sparse vector index\ny: result vector\no1: index offset\ncnt: counter\nadj: adjoint propagated up to the current node\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.hdrpass-Union{Tuple{T2}, Tuple{T1}, Tuple{T1, T2, Vararg{Any, 6}}} where {T1<:ExaModels.SecondAdjointNode1, T2<:ExaModels.SecondAdjointNode1}","page":"API Manual","title":"ExaModels.hdrpass","text":"hdrpass(t1::T1, t2::T2, comp, y1, y2, o2, cnt, adj)\n\nPerforms sparse hessian evaluation ((df1/dx)(df2/dx)' portion) via the reverse pass on the computation (sub)graph formed by second-order forward pass\n\nArguments:\n\nt1: second-order computation (sub)graph regarding f1\nt2: second-order computation (sub)graph regarding f2\ncomp: a Compressor, which helps map counter to sparse vector index\ny1: result vector #1\ny2: result vector #2 (only used when evaluating sparsity)\no2: index offset\ncnt: counter\nadj: second adjoint propagated up to the current node\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.jrpass-Union{Tuple{D}, Tuple{D, Vararg{Any, 7}}} where D<:Union{Real, ExaModels.AdjointNull}","page":"API Manual","title":"ExaModels.jrpass","text":"jrpass(d::D, comp, i, y1, y2, o1, cnt, adj)\n\nPerforms sparse jacobian evaluation via the reverse pass on the computation (sub)graph formed by forward pass\n\nArguments:\n\nd: first-order computation (sub)graph\ncomp: a Compressor, which helps map counter to sparse vector index\ni: constraint index (this is i-th constraint)\ny1: result vector #1\ny2: result vector #2 (only used when evaluating sparsity)\no1: index offset\ncnt: counter\nadj: adjoint propagated up to the current node\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.multipliers-Tuple{SolverCore.AbstractExecutionStats, ExaModels.Constraint}","page":"API Manual","title":"ExaModels.multipliers","text":"multipliers(result, y)\n\nReturns the multipliers for constraints y associated with result, obtained by solving the model.\n\nExample\n\njulia> using ExaModels, NLPModelsIpopt\n\njulia> c = ExaCore(concrete = Val(true));\n\njulia> c, x = add_var(c, 1:10; lvar = -1, uvar = 1);\n\njulia> c, _ = add_obj(c, (x[i]-2)^2 for i in 1:10);\n\njulia> c, y = add_con(c, x[i] + x[i+1] for i=1:9; lcon = -1, ucon = (1+i for i=1:9));\n\njulia> m = ExaModel(c);\n\njulia> result = ipopt(m; print_level=0);\n\njulia> val = multipliers(result, y);\n\n\njulia> val[1] ≈ 0.81933930\ntrue\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.multipliers_L-Tuple{SolverCore.AbstractExecutionStats, Any}","page":"API Manual","title":"ExaModels.multipliers_L","text":"multipliers_L(result, x)\n\nReturns the lower-bound dual variables for variable block x associated with result, obtained by solving the model.\n\nmultipliers_L[i] ≥ 0 is the dual variable for the bound constraint x[i] ≥ lvar[i]. A nonzero value indicates that the lower bound is active at the solution; the magnitude measures how much the objective would improve if that bound were relaxed.\n\nExample\n\njulia> using ExaModels, NLPModelsIpopt\n\njulia> c = ExaCore(concrete = Val(true));\n\njulia> c, x = add_var(c, 1:10; lvar = -1, uvar = 1);\n\njulia> c, _ = add_obj(c, (x[i]-2)^2 for i in 1:10);\n\njulia> m = ExaModel(c);\n\njulia> result = ipopt(m; print_level=0);\n\njulia> val = multipliers_L(result, x);\n\njulia> isapprox(val, fill(0, 10), atol=sqrt(eps(Float64)), rtol=Inf)\ntrue\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.multipliers_U-Tuple{SolverCore.AbstractExecutionStats, Any}","page":"API Manual","title":"ExaModels.multipliers_U","text":"multipliers_U(result, x)\n\nReturns the upper-bound dual variables for variable block x associated with result, obtained by solving the model.\n\nmultipliers_U[i] ≥ 0 is the dual variable for the bound constraint x[i] ≤ uvar[i]. A nonzero value indicates that the upper bound is active at the solution; the magnitude measures how much the objective would improve if that bound were relaxed.\n\nExample\n\njulia> using ExaModels, NLPModelsIpopt\n\njulia> c = ExaCore(concrete = Val(true));\n\njulia> c, x = add_var(c, 1:10; lvar = -1, uvar = 1);\n\njulia> c, _ = add_obj(c, (x[i]-2)^2 for i in 1:10);\n\njulia> m = ExaModel(c);\n\njulia> result = ipopt(m; print_level=0);\n\njulia> val = multipliers_U(result, x);\n\njulia> isapprox(val, fill(2, 10), atol=sqrt(eps(Float64)), rtol=Inf)\ntrue\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.objective-Tuple{LegacyExaCore, Vararg{Any}}","page":"API Manual","title":"ExaModels.objective","text":"objective(core, generator)\n\nDeprecated. Use add_obj instead.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.parameter-Tuple{LegacyExaCore, AbstractArray}","page":"API Manual","title":"ExaModels.parameter","text":"parameter(core, start::AbstractArray)\n\nDeprecated. Use add_par instead.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.set_parameter!-Tuple{ExaCore, ExaModels.Parameter, AbstractArray}","page":"API Manual","title":"ExaModels.set_parameter!","text":"set_parameter!(core, param, values)\n\nUpdates the values of parameters in the core.\n\nExample\n\njulia> using ExaModels\n\njulia> c = ExaCore(concrete = Val(true));\n\njulia> c, p = add_par(c, ones(5));\n\njulia> set_parameter!(c, p, ones(5))\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.sgradient!-NTuple{5, Any}","page":"API Manual","title":"ExaModels.sgradient!","text":"sgradient!(y, f, x, adj)\n\nPerforms sparse gradient evalution\n\nArguments:\n\ny: result vector\nf: the function to be differentiated in SIMDFunction format\nx: variable vector\nadj: initial adjoint\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.shessian!-NTuple{7, Any}","page":"API Manual","title":"ExaModels.shessian!","text":"shessian!(y1, y2, f, x, adj1, adj2)\n\nPerforms sparse jacobian evalution\n\nArguments:\n\ny1: result vector #1\ny2: result vector #2 (only used when evaluating sparsity)\nf: the function to be differentiated in SIMDFunction format\nx: variable vector\nadj1: initial first adjoint\nadj2: initial second adjoint\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.sjacobian!-NTuple{6, Any}","page":"API Manual","title":"ExaModels.sjacobian!","text":"sjacobian!(y1, y2, f, x, adj)\n\nPerforms sparse jacobian evalution\n\nArguments:\n\ny1: result vector #1\ny2: result vector #2 (only used when evaluating sparsity)\nf: the function to be differentiated in SIMDFunction format\nx: variable vector\nadj: initial adjoint\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.solution-Tuple{SolverCore.AbstractExecutionStats, Any}","page":"API Manual","title":"ExaModels.solution","text":"solution(result, x)\n\nReturns the primal solution values for variable block x associated with result, obtained by solving the model. The returned array has the same shape as x.\n\nExample\n\njulia> using ExaModels, NLPModelsIpopt\n\njulia> c = ExaCore(concrete = Val(true));\n\njulia> c, x = add_var(c, 1:10; lvar = -1, uvar = 1);\n\njulia> c, _ = add_obj(c, (x[i]-2)^2 for i in 1:10);\n\njulia> m = ExaModel(c);\n\njulia> result = ipopt(m; print_level=0);\n\njulia> val = solution(result, x);\n\njulia> isapprox(val, fill(1, 10), atol=sqrt(eps(Float64)), rtol=Inf)\ntrue\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.subexpr-Tuple{LegacyExaCore, Vararg{Any}}","page":"API Manual","title":"ExaModels.subexpr","text":"subexpr(core, generator; kwargs...)\n\nDeprecated. Use add_expr instead.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.variable-Tuple{LegacyExaCore, Vararg{Any}}","page":"API Manual","title":"ExaModels.variable","text":"variable(core, dims...; start = 0, lvar = -Inf, uvar = Inf, kwargs...)\n\nDeprecated. Use add_var instead.\n\n\n\n\n\n","category":"method"},{"location":"core/#ExaModels.@add_con!-Tuple","page":"API Manual","title":"ExaModels.@add_con!","text":"@add_con!(core, c1, generator; kwargs...)\n\nMacro interface for add_con!. Updates core in the calling scope and returns the new ConstraintAugmentation. Equivalent to c, aug = add_con!(c, c1, generator).\n\nThe generator must yield idx => expr pairs, where idx is an index into c1 and expr is the scalar term to accumulate into that constraint row.  See add_con! for full semantics and usage notes.\n\nExample\n\nc = ExaCore(concrete = Val(true))\n@add_var(c, x, 10)\n@add_con(c, g, x[i] + x[i+1] for i in 1:9; lcon = -1, ucon = 1)\n\n## Append sin(x[i+1]) to rows 4–6 of g:\naug = @add_con!(c, g, i => sin(x[i+1]) for i in 4:6)\n\n## Power-flow pattern — multiple augmentations on the same base constraint:\n## @add_con!(c, bus_balance, arc.bus => p[arc.i]   for arc in data.arc)\n## @add_con!(c, bus_balance, gen.bus => -pg[gen.i] for gen in data.gen)\n\n\n\n\n\n","category":"macro"},{"location":"core/#ExaModels.@add_con-Tuple","page":"API Manual","title":"ExaModels.@add_con","text":"@add_con(core, [name,] generator; kwargs...)\n\nMacro interface for add_con. Updates core in the calling scope.\n\nNamed (@add_con(core, g, generator)): binds g to the new Constraint in the local scope and registers it in core for later retrieval as core.g or model.g.\nAnonymous (@add_con(core, generator)): equivalent to c, g = add_con(c, generator).\n\nAccepts the same keyword arguments as add_con (lcon, ucon, start, etc.).\n\nExample\n\nc = ExaCore(concrete = Val(true))\n@add_var(c, x, 10)\n@add_con(c, g, x[i] + x[i+1] for i in 1:9; lcon = -1, ucon = 1)  # g in scope; c.g also works\n\n\n\n\n\n","category":"macro"},{"location":"core/#ExaModels.@add_expr-Tuple","page":"API Manual","title":"ExaModels.@add_expr","text":"@add_expr(core, [name,] generator; kwargs...)\n\nMacro interface for add_expr. Updates core in the calling scope.\n\nNamed (@add_expr(core, s, generator)): binds s to the new Expression in the local scope and registers it in core for later retrieval as core.s or model.s.\nAnonymous (@add_expr(core, generator)): equivalent to c, s = add_expr(c, generator).\n\nExample\n\nc = ExaCore(concrete = Val(true))\n@add_var(c, x, 10)\n@add_expr(c, s, x[i]^2 for i in 1:10)    # s in scope; c.s also works\n@add_obj(c, s[i] + s[i+1] for i in 1:9)\n\n\n\n\n\n","category":"macro"},{"location":"core/#ExaModels.@add_obj-Tuple","page":"API Manual","title":"ExaModels.@add_obj","text":"@add_obj(core, [name,] generator; kwargs...)\n\nMacro interface for add_obj. Updates core in the calling scope.\n\nNamed (@add_obj(core, f, generator)): binds f to the new Objective in the local scope and registers it in core for later retrieval as core.f or model.f.\nAnonymous (@add_obj(core, generator)): equivalent to c, o = add_obj(c, generator).\n\nExample\n\nc = ExaCore(concrete = Val(true))\n@add_var(c, x, 10)\n@add_obj(c, x[i]^2 for i in 1:10)\n\n\n\n\n\n","category":"macro"},{"location":"core/#ExaModels.@add_par-Tuple","page":"API Manual","title":"ExaModels.@add_par","text":"@add_par(core, [name,] start; kwargs...)\n\nMacro interface for add_par. Updates core in the calling scope.\n\nNamed (@add_par(core, θ, start)): binds θ to the new Parameter in the local scope and registers it in core for later retrieval as core.θ or model.θ.\nAnonymous (@add_par(core, start)): equivalent to c, p = add_par(c, start).\n\nExample\n\nc = ExaCore(concrete = Val(true))\n@add_par(c, θ, ones(10))  # θ is now in scope; c.θ also works\n\n\n\n\n\n","category":"macro"},{"location":"core/#ExaModels.@add_var-Tuple","page":"API Manual","title":"ExaModels.@add_var","text":"@add_var(core, [name,] dims...; kwargs...)\n\nMacro interface for add_var. Updates core in the calling scope.\n\nNamed (@add_var(core, x, dims...)): binds x to the new Variable in the local scope and registers it in core for later retrieval as core.x or model.x.\nAnonymous (@add_var(core, dims...)): equivalent to c, v = add_var(c, dims...).\n\nAccepts the same keyword arguments as add_var.\n\nExample\n\nc = ExaCore(concrete = Val(true))\n@add_var(c, x, 10; lvar = -1, uvar = 1)  # x is now in scope; c.x also works\n@add_var(c, y, 1:5)                        # y is in scope; c.y also works\n\n\n\n\n\n","category":"macro"},{"location":"core/#ExaModels.@register_bivariate-NTuple{6, Any}","page":"API Manual","title":"ExaModels.@register_bivariate","text":"@register_bivariate(f, df1, df2, ddf11, ddf12, ddf22)\n\nRegister a bivariate function f so it can be used inside @add_obj / @add_con expressions.  The macro adds four method groups:\n\nNode OP Node — f(d1::AbstractNode, d2::AbstractNode) → Node2(f, d1, d2).\nNode OP Real — f(d1::AbstractNode, d2::Real) → Node2(f, d1, d2). Numeric scalars (including iterator-derived values like factorial(j)) are stored directly in Node2 without wrapping in Constant.\nReal OP Node — symmetric counterpart of the above.\nConstant folding — f(Constant{I1}(), Constant{I2}()) → Constant(f(I1, I2)). Both-constant expressions are evaluated immediately.\n\nArguments\n\nf:     the function to register\ndf1:   partial derivative w.r.t. the first argument\ndf2:   partial derivative w.r.t. the second argument\nddf11: second partial w.r.t. the first argument\nddf12: mixed second partial\nddf22: second partial w.r.t. the second argument\n\nExample\n\njulia> using ExaModels\n\njulia> relu23(x,y) = (x > 0 || y > 0) ? (x + y)^3 : zero(x)\nrelu23 (generic function with 1 method)\n\njulia> drelu231(x,y) = (x > 0 || y > 0) ? 3 * (x + y)^2 : zero(x)\ndrelu231 (generic function with 1 method)\n\njulia> drelu232(x,y) = (x > 0 || y > 0) ? 3 * (x + y)^2  : zero(x)\ndrelu232 (generic function with 1 method)\n\njulia> ddrelu2311(x,y) = (x > 0 || y > 0) ? 6 * (x + y) : zero(x)\nddrelu2311 (generic function with 1 method)\n\njulia> ddrelu2312(x,y) = (x > 0 || y > 0) ? 6 * (x + y) : zero(x)\nddrelu2312 (generic function with 1 method)\n\njulia> ddrelu2322(x,y) = (x > 0 || y > 0) ? 6 * (x + y) : zero(x)\nddrelu2322 (generic function with 1 method)\n\njulia> @register_bivariate(relu23, drelu231, drelu232, ddrelu2311, ddrelu2312, ddrelu2322)\n\n\n\n\n\n","category":"macro"},{"location":"core/#ExaModels.@register_univariate-Tuple{Any, Any, Any}","page":"API Manual","title":"ExaModels.@register_univariate","text":"@register_univariate(f, df, ddf)\n\nRegister a univariate function f so it can be used inside @add_obj / @add_con expressions.  The macro adds three method groups:\n\nPrimal graph node — f(n::AbstractNode) → Node1(f, n). Applied at model-construction time to build the symbolic graph.\nConstant folding — f(::Constant{T}) → Constant(f(T)). When the argument is a Constant (value encoded as a type parameter), the result is evaluated immediately and stored as a new Constant, avoiding a Node1 allocation entirely.\nAdjoint / second-adjoint nodes — forward-pass nodes for gradient and Hessian computation, using df and ddf as the derivative functions.\n\nArguments\n\nf:   the function to register\ndf:  first derivative f'(x)\nddf: second derivative f''(x)\n\nExample\n\njulia> using ExaModels\n\njulia> relu3(x) = x > 0 ? x^3 : zero(x)\nrelu3 (generic function with 1 method)\n\njulia> drelu3(x) = x > 0 ? 3*x^2 : zero(x)\ndrelu3 (generic function with 1 method)\n\njulia> ddrelu3(x) = x > 0 ? 6*x : zero(x)\nddrelu3 (generic function with 1 method)\n\njulia> @register_univariate(relu3, drelu3, ddrelu3)\n\n\n\n\n\n","category":"macro"},{"location":"upgrade/#Upgrading-from-v0.9-to-v0.10","page":"Upgrading from v0.9 to v0.10","title":"Upgrading from v0.9 to v0.10","text":"This page documents the breaking API changes between ExaModels v0.9 and v0.10. It is written to be directly usable as a prompt for a code-migration agent.\n\n","category":"section"},{"location":"upgrade/#Summary-for-an-automated-migration-agent","page":"Upgrading from v0.9 to v0.10","title":"Summary for an automated migration agent","text":"The following is a complete, machine-readable description of every rename. Apply each substitution globally to all .jl files that import ExaModels.","category":"section"},{"location":"upgrade/#1.-Model-building-function-and-macro-renames","page":"Upgrading from v0.9 to v0.10","title":"1. Model-building function and macro renames","text":"Every old name has a direct one-to-one replacement. The old mutating style (x = variable(c, ...)) is now deprecated; use the functional style (c, x = add_var(c, ...)) or the macro style (@add_var(c, x, ...)).\n\nv0.9 function v0.10 function v0.10 macro\nvariable(c, ...) add_var(c, ...) → returns (c, var) @add_var(c, x, ...)\nparameter(c, ...) add_par(c, ...) → returns (c, par) @add_par(c, θ, ...)\nconstraint(c, ...) add_con(c, ...) → returns (c, con) @add_con(c, g, ...)\nconstraint!(c, c1, ...) add_con!(c, c1, ...) → returns (c, aug) @add_con!(c, g, ...)\nobjective(c, ...) add_obj(c, ...) → returns (c, obj) @add_obj(c, f, ...)\nsubexpr(c, ...) add_expr(c, ...) → returns (c, expr) @add_expr(c, s, ...)","category":"section"},{"location":"upgrade/#2.-ExaCore-and-LegacyExaCore","page":"Upgrading from v0.9 to v0.10","title":"2. ExaCore and LegacyExaCore","text":"In v0.9, ExaCore was a mutable struct that was modified in-place by each model-building call.\n\nIn v0.10, ExaCore is an immutable struct.  For backward compatibility, ExaCore() (i.e. concrete = Val(false), the default) returns a LegacyExaCore — a thin mutable wrapper that supports the deprecated mutating wrappers (variable, parameter, objective, constraint, constraint!, subexpr).  A deprecation warning is emitted at construction time to signal that this path will be removed in a future release.\n\nNote that LegacyExaCore does not support the new functional add_* API. Migrate to ExaCore(concrete = Val(true)) to use add_var, add_obj, etc.\n\nTo obtain the bare immutable ExaCore — required for type-stable code and AOT compilation with juliac — pass concrete = Val(true):\n\n# v0.9\nc = ExaCore()\nx = variable(c, 10; lvar = 0.0)\nobjective(c, x[i]^2 for i in 1:10)\nm = ExaModel(c)\n\n# v0.10 — functional style (recommended)\nc = ExaCore(concrete = Val(true))\nc, x = add_var(c, 10; lvar = 0.0)\nc, _  = add_obj(c, x[i]^2 for i in 1:10)\nm = ExaModel(c)\n\n# v0.10 — macro style (most concise)\nc = ExaCore(concrete = Val(true))\n@add_var(c, x, 10; lvar = 0.0)\n@add_obj(c, x[i]^2 for i in 1:10)\nm = ExaModel(c)","category":"section"},{"location":"upgrade/#3.-Mechanical-substitution-rules","page":"Upgrading from v0.9 to v0.10","title":"3. Mechanical substitution rules","text":"Apply these regex/string substitutions in order to any v0.9 file. Each rule is written as OLD → NEW.\n\nvariable(     →  add_var(          # only when first arg is an ExaCore\nparameter(    →  add_par(\nobjective(    →  add_obj(\nconstraint!(  →  add_con!(         # must come before constraint( rule\nconstraint(   →  add_con(\nsubexpr(      →  add_expr(\n\nAfter renaming the call sites, update the call pattern and switch to the immutable ExaCore:\n\n# Old: result assigned directly, c mutated in-place\nc = ExaCore()\nx = variable(c, ...)\n\n# New: functional pair destructuring, c rebound to updated immutable\nc = ExaCore(concrete = Val(true))\nc, x = add_var(c, ...)","category":"section"},{"location":"upgrade/#4.-ExaModelsLinearAlgebra-renamed-to-ExaModelsOptimalControl","page":"Upgrading from v0.9 to v0.10","title":"4. ExaModelsLinearAlgebra renamed to ExaModelsOptimalControl","text":"The extension that provides LinearAlgebra operations (dot, cross, det, norm, tr, diagm, diag, matrix–vector products) on ExaModels expression nodes was called ExaModelsLinearAlgebra in v0.9.  It is now ExaModelsOptimalControl and is triggered by loading LinearAlgebra:\n\nusing ExaModels, LinearAlgebra   # triggers ExaModelsOptimalControl automatically\n\nNo import of a separate package is needed.","category":"section"},{"location":"upgrade/#5.-Complete-before/after-example","page":"Upgrading from v0.9 to v0.10","title":"5. Complete before/after example","text":"# ── v0.9 ────────────────────────────────────────────────────────────────────\nusing ExaModels\n\nn = 100\nc = ExaCore()\nx = variable(c, n; lvar = -1.0, uvar = 1.0, start = 0.0)\nθ = parameter(c, ones(n))\ns = subexpr(c, θ[i] * x[i]^2 for i in 1:n)\ng = constraint(c, x[i] + x[i+1] for i in 1:n-1; lcon = -1.0, ucon = 1.0)\nconstraint!(c, g, i => sin(x[i+1]) for i in 1:n-1)\nobjective(c, s[i] for i in 1:n)\nm = ExaModel(c)\n\n# ── v0.10 (functional) ───────────────────────────────────────────────────────\nusing ExaModels\n\nn = 100\nc = ExaCore(concrete = Val(true))\nc, x = add_var(c, n; lvar = -1.0, uvar = 1.0, start = 0.0)\nc, θ = add_par(c, ones(n))\nc, s = add_expr(c, θ[i] * x[i]^2 for i in 1:n)\nc, g = add_con(c, x[i] + x[i+1] for i in 1:n-1; lcon = -1.0, ucon = 1.0)\nc, _ = add_con!(c, g, i => sin(x[i+1]) for i in 1:n-1)\nc, _ = add_obj(c, s[i] for i in 1:n)\nm = ExaModel(c)\n\n# ── v0.10 (macro) ────────────────────────────────────────────────────────────\nusing ExaModels\n\nn = 100\nc = ExaCore(concrete = Val(true))\n@add_var(c, x, n; lvar = -1.0, uvar = 1.0, start = 0.0)\n@add_par(c, θ, ones(n))\n@add_expr(c, s, θ[i] * x[i]^2 for i in 1:n)\n@add_con(c, g, x[i] + x[i+1] for i in 1:n-1; lcon = -1.0, ucon = 1.0)\n@add_con!(c, g, i => sin(x[i+1]) for i in 1:n-1)\n@add_obj(c, s[i] for i in 1:n)\nm = ExaModel(c)","category":"section"},{"location":"simd/#simd","page":"Mathematical Abstraction","title":"SIMD Abstraction","text":"In this page, we explain what SIMD abstraction of nonlinear program is, and why it can be beneficial for scalable optimization of large-scale optimization problems. More discussion can be found in our paper.","category":"section"},{"location":"simd/#What-is-SIMD-abstraction?","page":"Mathematical Abstraction","title":"What is SIMD abstraction?","text":"The mathematical statement of the problem formulation is as follows.\n\nbeginaligned\n  min_x^flatleq x leq x^sharp\n   sum_linLsum_iin I_l f^(l)(x p^(l)_i)\n  textst g^flat leq leftg^(m)(x q_j)right_jin J_m +sum_nin N_msum_kin K_nh^(n)(x s^(n)_k) leq g^sharpquad forall minM\nendaligned\n\nwhere f^(ell)(cdotcdot), g^(m)(cdotcdot), and h^(n)(cdotcdot) are twice differentiable functions with respect to the first argument, whereas p^(k)_i_iin N_k_kinK, q^(k)_i_iin M_l_minM, and s^(n)_k_kinK_n_ninN_m_minM are problem data, which can either be discrete or continuous. It is also assumed that our functions f^(l)(cdotcdot), g^(m)(cdotcdot), and h^(n)(cdotcdot) can be expressed with computational graphs of moderate length. ","category":"section"},{"location":"simd/#Why-SIMD-abstraction?","page":"Mathematical Abstraction","title":"Why SIMD abstraction?","text":"Many physics-based models, such as AC OPF, have a highly repetitive structure. One of the manifestations of it is that the mathematical statement of the model is concise, even if the practical model may contain millions of variables and constraints. This is possible due to the use of repetition over a certain index and data sets. For example, it suffices to use 15 computational patterns to fully specify the AC OPF model. These patterns arise from (1) generation cost, (2) reference bus voltage angle constraint, (3-6) active and reactive power flow (from and to), (7) voltage angle difference constraint, (8-9) apparent power flow limits (from and to), (10-11) power balance equations, (12-13) generators' contributions to the power balance equations, and (14-15) in/out flows contributions to the power balance equations. However, such repetitive structure is not well exploited in the standard NLP modeling paradigms. In fact, without the SIMD abstraction, it is difficult for the AD package to detect the parallelizable structure within the model, as it will require the full inspection of the computational graph over all expressions.  By preserving the repetitive structures in the model, the repetitive structure can be directly available in AD implementation.\n\nUsing the multiple dispatch feature of Julia, ExaModels.jl generates highly efficient derivative computation code, specifically compiled for each computational pattern in the model. These derivative evaluation codes can be run over the data in various GPU array formats, and implemented via array and kernel programming in Julia Language. In turn, ExaModels.jl has the capability to efficiently evaluate first and second-order derivatives using GPU accelerators.","category":"section"},{"location":"jump/#JuMP-Interface-(Experimental)","page":"JuMP Interface (experimental)","title":"JuMP Interface (Experimental)","text":"","category":"section"},{"location":"jump/#JuMP-to-an-ExaModel","page":"JuMP Interface (experimental)","title":"JuMP to an ExaModel","text":"We have an experimental interface to JuMP model. A JuMP model can be directly converted to a ExaModel. It is as simple as this:\n\nusing ExaModels, JuMP, CUDA\n\nN = 10\njm = Model()\n\n@variable(jm, x[i=1:N], start = mod(i, 2) == 1 ? -1.2 : 1.0)\n@constraint(\n    jm,\n    s[i=1:(N-2)],\n    3x[i+1]^3 + 2x[i+2] - 5 + sin(x[i+1] - x[i+2])sin(x[i+1] + x[i+2]) + 4x[i+1] -\n    x[i]exp(x[i] - x[i+1]) - 3 == 0.0\n)\n@objective(jm, Min, sum(100(x[i-1]^2 - x[i])^2 + (x[i-1] - 1)^2 for i = 2:N))\n\nem = ExaModel(jm; backend = CUDABackend())\n\nAn ExaModel{Float64, CUDA.CuArray{Float64, 1, CUDA.DeviceMemory}, ...}\n\n  Problem name: Generic\n   All variables: ████████████████████ 10     All constraints: ████████████████████ 8     \n            free: ████████████████████ 10                free: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n           lower: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                lower: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n           upper: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                upper: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n         low/upp: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0              low/upp: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n           fixed: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0                fixed: ████████████████████ 8     \n          infeas: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0               infeas: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n            nnzh: (-212.73% sparsity)   172             linear: ⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅⋅ 0     \n                                                    nonlinear: ████████████████████ 8     \n                                                         nnzj: (  0.00% sparsity)   80    \n                                                     lin_nnzj: (------% sparsity)         \n                                                     nln_nnzj: (  0.00% sparsity)   80    \n\n\n\nHere, note that only scalar objective/constraints created via @constraint and @objective API are supported. Older syntax like @NLconstraint and @NLobjective are not supported. We can solve the model using any of the solvers supported by ExaModels. For example, we can use MadNLP:\n\nusing MadNLPGPU\n\nresult = madnlp(em)\n\n\"Execution stats: Optimal Solution Found (tol = 1.0e-04).\"","category":"section"},{"location":"jump/#JuMP-Optimizer","page":"JuMP Interface (experimental)","title":"JuMP Optimizer","text":"Alternatively, one can use the Optimizer interface provided by ExaModels. This feature can be used as follows.\n\nusing ExaModels, JuMP, CUDA\nusing MadNLPGPU\n\nset_optimizer(jm, () -> ExaModels.MadNLPOptimizer(CUDABackend()))\noptimize!(jm)\n\nThis is \u001b[34mMad\u001b[31mN\u001b[32mL\u001b[35mP\u001b[0m version v0.9.1, running with cuDSS v0.7.1\n\nNumber of nonzeros in constraint Jacobian............:       80\nNumber of nonzeros in Lagrangian Hessian.............:      172\n\nTotal number of variables............................:       10\n                     variables with only lower bounds:        0\n                variables with lower and upper bounds:        0\n                     variables with only upper bounds:        0\nTotal number of equality constraints.................:        8\nTotal number of inequality constraints...............:        0\n        inequality constraints with only lower bounds:        0\n   inequality constraints with lower and upper bounds:        0\n        inequality constraints with only upper bounds:        0\n\niter    objective    inf_pr   inf_du inf_compl lg(mu) lg(rg) alpha_pr ir ls\n   0  2.0570000e+03 2.48e+01 1.00e+02 3.96e-04  -1.0     -   0.00e+00  0  0 \n   1  2.0474072e+03 2.47e+01 2.97e+01 4.03e-02  -1.0     -   4.00e-03  1  1h\n   2  1.1009058e+03 1.49e+01 2.24e+01 2.02e-02  -1.0     -   1.00e+00  1  1h\n   3  1.1598223e+02 2.15e+00 5.34e+01 2.00e-02  -1.0     -   1.00e+00  1  1h\n   4  6.5263509e+00 1.12e-01 4.74e+00 2.00e-02  -1.0     -   1.00e+00  1  1h\n   5  6.2326771e+00 1.64e-03 2.08e-02 2.00e-02  -1.0     -   1.00e+00  1  1h\n   6  6.2324576e+00 1.18e-06 1.22e-05 3.87e-04  -3.8     -   1.00e+00  1  1h\n   7  6.2323021e+00 5.36e-11 1.98e-06 8.81e-05  -5.0     -   1.00e+00  1  1h\n\nNumber of Iterations....: 7\n\n                                   (scaled)                 (unscaled)\nObjective...............:   7.8690682927808797e-01    6.2323020878824575e+00\nDual infeasibility......:   1.9831098658773527e-06    1.5706230137748636e-05\nConstraint violation....:   5.3644534025673336e-11    5.3644534025673336e-11\nComplementarity.........:   1.1122043961249384e-05    8.8086588173095132e-05\nOverall NLP error.......:   8.8086588173095132e-05    8.8086588173095132e-05\n\nNumber of objective function evaluations              = 8\nNumber of objective gradient evaluations              = 8\nNumber of constraint evaluations                      = 8\nNumber of constraint Jacobian evaluations             = 8\nNumber of Lagrangian Hessian evaluations              = 7\nNumber of KKT factorizations                          = 7\nNumber of KKT backsolves                              = 7\n\nTotal wall secs in initialization                     =  0.606 s\nTotal wall secs in linear solver                      =  unavailable\nTotal wall secs in NLP function evaluations           =  0.003 s\nTotal wall secs in solver (w/o init./fun./lin. alg.)  =  unavailable\nTotal wall secs                                       =  3.779 s\n\n\u001b[32mEXIT: Optimal Solution Found (tol = 1.0e-04).\u001b[0m\n\n\nAgain, only scalar objective/constraints created via @constraint and @objective API are supported. Older syntax like @NLconstraint and @NLobjective are not supported.\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"gpu/#CPU-and-GPU-acceleration","page":"CPU and GPU acceleration","title":"CPU and GPU acceleration","text":"One of the key features of ExaModels.jl is being able to evaluate derivatives either on multi-threaded CPUs or GPU accelerators. Currently, GPU acceleration is only tested for NVIDIA GPUs. If you'd like to use multi-threaded CPU acceleration, start julia with\n\n$ julia -t 4 # using 4 threads\n\nAlso, if you're using NVIDIA GPUs, make sure to have installed appropriate drivers.\n\nLet's say that our CPU code is as follows.\n\nusing ExaModels\nfunction luksan_vlcek_obj(x, i)\n    return 100 * (x[i-1]^2 - x[i])^2 + (x[i-1] - 1)^2\nend\n\nfunction luksan_vlcek_con(x, i)\n    return 3x[i+1]^3 + 2 * x[i+2] - 5 + sin(x[i+1] - x[i+2])sin(x[i+1] + x[i+2]) + 4x[i+1] -\n           x[i]exp(x[i] - x[i+1]) - 3\nend\n\nfunction luksan_vlcek_x0(i)\n    return mod(i, 2) == 1 ? -1.2 : 1.0\nend\n\nfunction luksan_vlcek_model(N)\n\n    c = ExaCore(concrete = Val(true))\n    @add_var(c, x, N; start = (luksan_vlcek_x0(i) for i = 1:N))\n    @add_con(c, luksan_vlcek_con(x, i) for i = 1:(N-2))\n    @add_obj(c, luksan_vlcek_obj(x, i) for i = 2:N)\n\n    return ExaModel(c)\nend\n\nluksan_vlcek_model (generic function with 1 method)\n\nNow we simply modify this by\n\nfunction luksan_vlcek_model(N, backend = nothing)\n\n    c = ExaCore(; backend = backend, concrete = Val(true)) # specify the backend\n    @add_var(c, x, N; start = (luksan_vlcek_x0(i) for i = 1:N))\n    @add_con(c, luksan_vlcek_con(x, i) for i = 1:(N-2))\n    @add_obj(c, luksan_vlcek_obj(x, i) for i = 2:N)\n\n    return ExaModel(c)\nend\n\nluksan_vlcek_model (generic function with 2 methods)\n\nThe acceleration can be done simply by specifying the backend. In particular, for multi-threaded CPUs,\n\nusing ExaModels, NLPModelsIpopt, KernelAbstractions\n\nm = luksan_vlcek_model(10, CPU())\nipopt(m)\n\n\"Execution stats: first-order stationary\"\n\nFor NVIDIA GPUs, we can use CUDABackend. However, currently, there are not many optimization solvers that are capable of solving problems on GPUs. The only option right now is using MadNLP.jl. To use this, first install\n\nimport Pkg; Pkg.add(\"MadNLPGPU\")\n\nThen, we can run:\n\nusing CUDA, MadNLPGPU\n\nm = luksan_vlcek_model(10, CUDABackend())\nmadnlp(m)\n\nIn the case we have arrays for the data, what we need to do is to simply convert the array types to the corresponding device array types. In particular,\n\nfunction cuda_luksan_vlcek_model(N)\n    c = ExaCore(; backend = CUDABackend(), concrete = Val(true))\n    d1 = CuArray(1:(N-2))\n    d2 = CuArray(2:N)\n    d3 = CuArray([luksan_vlcek_x0(i) for i = 1:N])\n\n    @add_var(c, x, N; start = d3)\n    @add_con(c, luksan_vlcek_con(x, i) for i in d1)\n    @add_obj(c, luksan_vlcek_obj(x, i) for i in d2)\n\n    return ExaModel(c)\nend\n\ncuda_luksan_vlcek_model (generic function with 1 method)\n\nm = cuda_luksan_vlcek_model(10)\nmadnlp(m)\n\nSince ExaModels builds on KernelAbstractions.jl, it can in principle target multiple hardware backends. The following backends are provided by the JuliaGPU ecosystem:\n\nCPU() for multi-threaded CPU execution\nCUDABackend() for NVIDIA GPUs (CUDA.jl)\nROCBackend() for AMD GPUs (AMDGPU.jl)\nOneAPIBackend() for Intel GPUs (oneAPI.jl)\nMetalBackend() for Apple GPUs (Metal.jl)\nOpenCLBackend() for generic OpenCL devices (OpenCL.jl)\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"ref/#References","page":"References","title":"References","text":"L. T. Biegler. Nonlinear programming: concepts, algorithms, and applications to chemical processes (SIAM, 2010).\n\n\n\nC. Coffrin, R. Bent, K. Sundar, Y. Ng and M. Lubin. PowerModels.jl: An open-source framework for exploring power flow formulations. In: 2018 Power Systems Computation Conference (PSCC) (IEEE, 2018); pp. 1–8.\n\n\n\nL. Lukšan and J. Vlček. Indefinitely preconditioned inexact Newton method for large sparse equality constrained non-linear programming problems. Numerical linear algebra with applications 5, 219–247 (1998).\n\n\n\n","category":"section"},{"location":"#Introduction","page":"Introduction","title":"Introduction","text":"Welcome to the documentation of ExaModels.jl\t\n\nnote: Note\nExaModels runs on julia VERSION ≥ v\"1.9\"\n\nwarning: Warning\nPlease help us improve ExaModels and this documentation! ExaModels is in the early stage of development, and you may encounter unintended behaviors or missing documentations. If you find anything is not working as intended or documentation is missing, please open issues or pull requests or start discussions. ","category":"section"},{"location":"#What-is-ExaModels.jl?","page":"Introduction","title":"What is ExaModels.jl?","text":"ExaModels.jl is an algebraic modeling and automatic differentiation tool in Julia Language, specialized for SIMD abstraction of nonlinear programs. ExaModels.jl employs what we call SIMD abstraction for nonlinear programs (NLPs), which allows for the preservation of the parallelizable structure within the model equations, facilitating efficient automatic differentiation either on the single-thread CPUs, multi-threaded CPUs, as well as GPU accelerators. More details about SIMD abstraction can be found here.","category":"section"},{"location":"#Key-differences-from-other-algebraic-modeling-tools","page":"Introduction","title":"Key differences from other algebraic modeling tools","text":"ExaModels.jl is different from other algebraic modeling tools, such as JuMP or AMPL, in the following ways:\n\nModeling Interface: ExaModels.jl requires users to specify the model equations always in the form of Generators. This restrictive structure allows ExaModels.jl to preserve the SIMD-compatible structure in the model equations. This unique feature distinguishes ExaModels.jl from other algebraic modeling tools.\nPerformance: ExaModels.jl compiles (via Julia's compiler) derivative evaluation codes tailored to each computation pattern. Through reverse-mode automatic differentiation using these tailored codes, ExaModels.jl achieves significantly faster derivative evaluation speeds, even when using CPU.\nPortability: ExaModels.jl goes beyond traditional boundaries of\n\nalgebraic modeling systems by enabling derivative evaluation on GPU accelerators. Implementation of GPU kernels is accomplished using the portable programming paradigm offered by KernelAbstractions.jl. With ExaModels.jl, you can run your code on various devices, including multi-threaded CPUs, NVIDIA GPUs, AMD GPUs, and Intel GPUs. Note that Apple's Metal is currently not supported due to its lack of support for double-precision arithmetic.\n\nThus, ExaModels.jl shines when your model has\n\nnonlinear objective and constraints;\na large number of variables and constraints;\nhighly repetitive structure;\nsparse Hessian and Jacobian.\n\nThese features are often exhibited in optimization problems associated with first-principle physics-based models. Primary examples include optimal control problems formulated with direct subscription method [1] and network system optimization problems, such as optimal power flow [2] and gas network control/estimation problems.","category":"section"},{"location":"#Performance-Highlights","page":"Introduction","title":"Performance Highlights","text":"ExaModels.jl significantly enhances the performance of derivative evaluations for nonlinear optimization problems that can benefit from SIMD abstraction. Recent benchmark results demonstrate this notable improvement. Notably, when solving the AC OPF problem for a 9241 bus system, derivative evaluation using ExaModels.jl on GPUs can be up to two orders of magnitude faster compared to JuMP or AMPL. Some benchmark results are available below. The following  problems are used for benchmarking:\n\nLuksanVlcek problem\nQuadrotor control problem\nDistillation column control problem\nAC optimal power flow problem\n\n(Image: benchmark)","category":"section"},{"location":"#Supported-Solvers","page":"Introduction","title":"Supported Solvers","text":"ExaModels can be used with any solver that can handle NLPModel data type, but several callbacks are not currently implemented, and cause some errors. Currently, it is tested with the following solvers:\n\nIpopt (via NLPModelsIpopt.jl)\nMadNLP.jl","category":"section"},{"location":"#Documentation-Structure","page":"Introduction","title":"Documentation Structure","text":"This documentation is structured in the following way.\n\nThe remainder of this page highlights several key aspects of ExaModels.jl.\nThe mathematical abstraction–-SIMD abstraction of nonlinear programming–-of ExaModels.jl is discussed in Mathematical Abstraction page.\nThe step-by-step tutorial of using ExaModels.jl can be found in Tutorial page.\nThis documentation does not intend to discuss the engineering behind the implementation of ExaModels.jl. Some high-level idea is discussed in a recent publication, but the full details of the engineering behind it will be discussed in the future publications.","category":"section"},{"location":"#Citing-ExaModels.jl","page":"Introduction","title":"Citing ExaModels.jl","text":"If you use ExaModels.jl in your research, we would greatly appreciate your citing this preprint.\n\n@misc{shin2023accelerating,\n      title={Accelerating Optimal Power Flow with {GPU}s: {SIMD} Abstraction of Nonlinear Programs and Condensed-Space Interior-Point Methods}, \n      author={Sungho Shin and Fran{\\c{c}}ois Pacaud and Mihai Anitescu},\n      year={2023},\n      eprint={2307.16830},\n      archivePrefix={arXiv},\n      primaryClass={math.OC}\n}","category":"section"},{"location":"#Supporting-ExaModels.jl","page":"Introduction","title":"Supporting ExaModels.jl","text":"Please report issues and feature requests via the GitHub issue tracker.\nQuestions are welcome at GitHub discussion forum.","category":"section"}]
}
